export interface Question { q: string; opts: string[]; a: number; fb: string; }
export interface Cours16Locale { questions: Question[]; }

const questionsFr: Question[] = [
  // Définition générale
  { q: "Qu'est-ce que la réharmonisation ?", opts: ["Jouer plus de notes", "Remplacer les accords d'une progression existante par d'autres tout en conservant la mélodie", "Changer la mélodie d'un morceau", "Transposer dans une autre tonalité"], a: 1, fb: "La réharmonisation conserve la mélodie mais remplace les accords. Condition fondamentale : chaque note mélodique doit être compatible avec le nouvel accord (fondamentale, tierce, quinte, septième ou extension). C'est de la sculpture harmonique." },
  { q: "Quelle est la condition fondamentale d'une réharmonisation réussie ?", opts: ["Utiliser des accords plus complexes", "La note mélodique doit être compatible avec le nouvel accord", "Toujours rester dans la même tonalité", "N'utiliser que la substitution tritonique"], a: 1, fb: "Chaque note mélodique doit appartenir au nouvel accord ou être une tension acceptable : fondamentale, tierce, quinte, septième ou extension (9e, 11e, 13e). Si la mélodie sonne faux sur le nouvel accord, la réharmonisation échoue." },
  { q: "Une note mélodique est compatible avec un accord si elle est :", opts: ["Uniquement la fondamentale", "Fondamentale, tierce, quinte, septième ou extension (9e/11e/13e)", "Seulement la tierce ou la quinte", "N'importe quelle note"], a: 1, fb: "Les notes compatibles : fondamentale (1), tierce (3), quinte (5), septième (7), et les extensions (9e, 11e, 13e). Si la mélodie chante Mi sur un accord réharmonisé, cet accord doit contenir Mi dans l'une de ces positions." },
  { q: "Réharmoniser une progression revient à :", opts: ["Changer le tempo", "Remplacer tout ou partie des accords en conservant la mélodie intacte", "Ajouter de nouveaux instruments", "Changer la tonalité"], a: 1, fb: "Réharmoniser = changer les accords, garder la mélodie. La mélodie est l'élément fixe ; les accords en dessous sont modifiables tant que chaque note mélodique reste compatible. C'est l'art de trouver de nouveaux 'habillages harmoniques' pour un même air." },

  // Substitution diatonique
  { q: "Quelle paire d'accords peut se substituer dans la substitution diatonique ?", opts: ["I et II", "I et VI", "V et IV", "III et VII"], a: 1, fb: "I et VI partagent deux à trois notes communes (en C : CMaj7 partage Mi et Sol avec Am7 — même Do). Cette proximité permet de les permuter sans affecter la mélodie. II et IV se substituent aussi (Dm7 et FMaj7 partagent Fa et La)." },
  { q: "En C majeur, quels accords se substituent dans la substitution diatonique ?", opts: ["CMaj7 ↔ Dm7", "CMaj7 ↔ Am7  ·  Dm7 ↔ FMaj7", "G7 ↔ Em7", "Dm7 ↔ G7"], a: 1, fb: "CMaj7 et Am7 partagent Mi et Sol (et Do). FMaj7 et Dm7 partagent Fa et La. Ces notes communes créent une continuité harmonique suffisante pour que la mélodie reste logique sur l'accord substitué." },
  { q: "Pourquoi I et VI peuvent-ils se substituer ?", opts: ["Car ils ont la même fondamentale", "Car ils partagent deux à trois notes communes", "Car ils sont à distance de triton", "Car ils ont la même qualité majeur/mineur"], a: 1, fb: "En C : CMaj7 = C E G B, Am7 = A C E G. Notes communes : Do, Mi, Sol. La mélodie sonne juste sur Am7 si elle chantait Do, Mi ou Sol sur CMaj7. Plus de notes communes = substitution plus naturelle." },
  { q: "La substitution diatonique 'II ↔ IV' en C majeur correspond à :", opts: ["Dm7 ↔ G7", "Dm7 ↔ FMaj7", "Am7 ↔ Em7", "CMaj7 ↔ FMaj7"], a: 1, fb: "IIm7 = Dm7 (D F A C), IV = FMaj7 (F A C E). Notes communes : Fa, La, Do. Ces deux accords ont une fonction sous-dominante similaire et peuvent se substituer dans beaucoup de contextes." },
  { q: "Remplacer CMaj7 par Am7 (I → VI) crée quel effet ?", opts: ["Une résolution plus forte", "Une légère couleur mineure, plus douce — 'résolution déceptive douce'", "Une tension maximale", "Un changement de tonalité"], a: 1, fb: "Am7 partage les notes de CMaj7 mais son fondement mineur crée une couleur plus douce, parfois mélancolique. C'est une 'cadence déceptive douce' — la résolution attendue sur I arrive mais teintée de VIm, moins définitive." },

  // Substitution tritonique
  { q: "Le substitut tritonique de G7 est :", opts: ["F#7", "Db7", "Ab7", "C#7"], a: 1, fb: "Db7 est situé un triton (6 demi-tons) au-dessus de G7. Db7 (Db F Ab Cb) partage le même triton que G7 (Si/Cb et Fa) — les notes de tension sont identiques mais leurs rôles s'inversent. La basse descend d'un demi-ton Db→C." },
  { q: "Que partagent G7 et Db7, rendant la substitution tritonique possible ?", opts: ["La fondamentale", "La même quinte", "Le même triton — Si et Fa (notes de tension)", "La même septième"], a: 2, fb: "G7 contient Si–Fa (triton). Db7 contient Fa–Cb (= Si, enharmonique). Ces deux notes de tension sont identiques dans les deux accords mais leurs noms s'inversent. C'est ce partage qui rend la substitution cohérente harmoniquement." },
  { q: "Quel effet crée la substitution tritonique sur la basse ?", opts: ["Un saut de quinte", "Un mouvement chromatique descendant (demi-ton) vers I", "Un mouvement ascendant par demi-tons", "Une basse fixe"], a: 1, fb: "Db7 → CMaj7 : la basse descend d'un demi-ton. Comparé à G7 → CMaj7 (quinte descendante), c'est bien plus élégant. Ce mouvement chromatique est caractéristique du jazz bebop et de la réharmonisation jazz." },
  { q: "Le substitut tritonique de D7 (dominante de GMaj7) est :", opts: ["Eb7", "Ab7", "Bb7", "F#7"], a: 1, fb: "Un triton au-dessus de D (Ré) = Ab (La bémol). Ab7 est le substitut tritonique de D7. En II–V–I de G : Am7–D7–GMaj7 peut devenir Am7–Ab7–GMaj7 (basse La–Lab–Sol, descente chromatique)." },
  { q: "Pourquoi la substitution tritonique fonctionne-t-elle harmoniquement ?", opts: ["Car les deux accords ont la même quinte", "Car V7 et ♭II7 partagent les mêmes notes de tension (le triton), juste avec les rôles inversés", "Car ils sont dans la même gamme", "Car la fondamentale reste la même"], a: 1, fb: "Le triton de V7 (ex. Si–Fa de G7) est aussi le triton de ♭II7 (Fa–Si de Db7). Les deux accords créent la même tension de résolution vers I — même 'carburant', fondamentale différente. La basse descend par demi-ton au lieu de quinte." },
  { q: "Dans 'Dm7 – Db7 – CMaj7', Db7 remplace quel accord original ?", opts: ["Dm7 (II)", "G7 (V) par substitution tritonique", "Am7 (VI)", "Em7 (III)"], a: 1, fb: "Db7 est le substitut tritonique de G7. La progression originale Dm7–G7–CMaj7 devient Dm7–Db7–CMaj7. La basse D–Db–C descend chromatiquement, rendant la progression très élégante." },

  // Emprunt modal
  { q: "Qu'est-ce qu'un emprunt modal en réharmonisation ?", opts: ["Utiliser un accord d'un autre instrument", "Remplacer un accord par son homonyme de la gamme mineure parallèle", "Utiliser le mode dorien", "Emprunter des accords au jazz modal"], a: 1, fb: "L'emprunt modal prend un accord de la tonalité homonyme mineure. En C majeur, on emprunte à C mineur : Fm (IVm), Cm (Im), AbMaj7 (bVI), Bb7 (bVII). Ces accords apportent une couleur sombre et modale dans un contexte majeur." },
  { q: "En C majeur, 'FMaj7 → Fm' est un emprunt de :", opts: ["La gamme de Fa majeur", "C mineur parallèle (IVm = Fm dans la gamme homonyme mineure)", "La gamme de Ré dorien", "La gamme pentatonique"], a: 1, fb: "Fm (F Ab C Eb) est le IVe degré de C mineur. On l'emprunte à la tonalité homonyme mineure. Lab (3ce de Fm) crée la couleur sombre. Bill Evans usait fréquemment de cette 'bémolisation' du IV dans ses standards." },
  { q: "Quelle note caractéristique apparaît quand on remplace FMaj7 par Fm en C majeur ?", opts: ["Fa#", "Lab (bIII de C mineur)", "Do#", "Sib"], a: 1, fb: "Fm = F Ab C Eb. Le Lab (Ab) est la note étrangère issue de C mineur. Cette bémolisation de la tierce (La→Lab) caractérise l'emprunt modal — couleur sombre immédiatement reconnaissable." },
  { q: "Quels accords peut-on emprunter à C mineur parallèle ?", opts: ["Uniquement Cm", "Fm (IVm), Cm (Im), AbMaj7 (bVI), Bb7 (bVII), EbMaj7 (bIII)", "Seulement Fm et Cm", "G7 et D7 seulement"], a: 1, fb: "La gamme de C mineur fournit : Im=Cm, IIm7b5=Dm7b5, bIII=EbMaj7, IVm=Fm, V7=G7, bVI=AbMaj7, bVII=Bb7. Tous peuvent être empruntés en C majeur. Les plus courants : Fm, AbMaj7, Bb7 (pour leurs bémols expressifs)." },
  { q: "Pourquoi l'emprunt modal crée-t-il un effet poignant ?", opts: ["Car c'est plus facile à jouer", "Car il introduit des bémols inattendus qui assombrissent momentanément une couleur majeure", "Car ça supprime le triton", "Car c'est imposé par la forme AABA"], a: 1, fb: "Les emprunts modaux (IV→IVm, I→Im) introduisent des bémols issus du mineur parallèle — Lab, Mib, Sib. Ces couleurs sombres inattendues dans un contexte majeur créent un contraste expressif puissant — signature du son de Bill Evans." },

  // Harmonisation parallèle
  { q: "Qu'est-ce que l'harmonisation parallèle ?", opts: ["Jouer deux mélodies simultanément", "Déplacer le même type d'accord chromatiquement sous la mélodie", "Harmoniser à la tierce", "Doubler les voix à l'octave"], a: 1, fb: "L'harmonisation parallèle déplace un type d'accord identique (ex. Maj7) chromatiquement ou par tons en suivant la mélodie. CMaj7–DbMaj7–DMaj7 : même structure, bases successives. Technique impressionniste adoptée par le jazz." },
  { q: "CMaj7 → DbMaj7 → DMaj7 est un exemple de :", opts: ["Substitution tritonique successive", "Harmonisation parallèle chromatique ascendante", "Substitution diatonique", "Cycle des quintes"], a: 1, fb: "Même type d'accord (Maj7) déplacé chromatiquement (C→Db→D). La conduite de voix est mécanique — toutes les voix bougent du même intervalle. La mélodie flottant au-dessus crée l'intérêt harmonique." },
  { q: "Quel compositeur est surtout associé à l'harmonisation parallèle ?", opts: ["Bach", "Beethoven", "Debussy", "Vivaldi"], a: 2, fb: "Debussy a systématisé les accords parallèles dans ses préludes et nocturnes. L'impressionnisme français a introduit cette technique que le jazz a adoptée — notamment Bill Evans sur My Foolish Heart et Peace Piece." },
  { q: "Dans l'harmonisation parallèle, qu'est-ce qui crée l'intérêt harmonique ?", opts: ["La complexité des accords", "La mélodie — les accords se déplacent en bloc sous elle", "Le mouvement de basse rapide", "Les notes de tension"], a: 1, fb: "Les accords parallèles sont 'neutres' en eux-mêmes. C'est la mélodie immuable qui crée la logique et l'intérêt. La succession chromatique des accords crée l'effet impressionniste ; la mélodie porte l'auditeur." },

  // Compatibilité mélodie/accord
  { q: "Si la mélodie chante 'Mi' sur un accord réharmonisé, quel accord convient ?", opts: ["Fm7 (Mi absent)", "CMaj7 (Mi = 3ce)", "Dm7b5 (Mi absent)", "Bb7 (Mi absent)"], a: 1, fb: "CMaj7 = C E G B. Mi (E) est la 3ce de CMaj7 — note constitutive. La mélodie Mi est parfaitement compatible. Règle : la note mélodique doit être 1, 3, 5, 7 ou extension de l'accord." },
  { q: "Si la mélodie chante 'La' sur un accord réharmonisé, lequel convient ?", opts: ["Dm7 (La = 5te)", "FMaj7 (La = 3ce)", "Am7 (La = fondamentale)", "Tous fonctionnent"], a: 3, fb: "La (A) est : 5te de Dm7, 3ce de FMaj7, fondamentale d'Am7. Les trois accords sont compatibles avec la mélodie La. C'est pourquoi la réharmonisation offre tant de possibilités — une même note peut appartenir à de nombreux accords." },
  { q: "Pour vérifier la compatibilité mélodie/accord, la note doit être :", opts: ["Plus haute que la basse", "1, 3, 5, 7 ou extension (9e, 11e, 13e) de l'accord", "Dans la même octave que la fondamentale", "Inférieure à la 5te"], a: 1, fb: "Règle universelle : fondamentale (1), tierce (3), quinte (5), septième (7) ou extension (9e, 11e, 13e). Les notes hors de ces catégories créent des frottements involontaires. Une b9 non intentionnelle sonne faux." },
  { q: "Pourquoi 'Si' (B naturel) est-il problématique sur un accord Fm ?", opts: ["Car Si est trop grave", "Car Si (= 4te augmentée / triton de Fm) n'est pas une extension naturelle d'un accord mineur", "Car Si est toujours dissonant", "Car Si est trop aigu"], a: 1, fb: "Fm = F Ab C Eb. Si (B) est la 4te augmentée de Fm — un triton par rapport à la fondamentale Fa. Ce n'est pas une extension naturelle. Si la mélodie chante Si au-dessus de Fm, la réharmonisation sonne faux : il faut choisir un autre accord." },
  { q: "Dans 'Dm7 – Db7 – CMaj7' avec mélodie Sol–Sol–Sol, Db7 est-il compatible ?", opts: ["Non — Sol est la 4te bémolisée de Db7, très dissonante", "Oui — Sol est la quinte de Db7", "Non — Sol n'est jamais compatible", "Oui — Sol est toujours possible"], a: 0, fb: "Db7 = Db F Ab Cb. Sol (G) par rapport à Db : c'est la quarte augmentée (= triton). Très dissonant, non naturel. Avant de valider une réharmonisation, vérifier chaque note mélodique sur chaque nouvel accord." },

  // Bill Evans
  { q: "Bill Evans est associé à quel courant du jazz ?", opts: ["Bebop des années 1940", "Jazz cool et post-bop des années 1950–70", "Free jazz", "Dixieland"], a: 1, fb: "Bill Evans (1929–1980) est une figure centrale du jazz cool et post-bop. Son jeu avec le Miles Davis Sextet (Kind of Blue, 1959) et son trio ont défini un son introspectif harmoniquement sophistiqué." },
  { q: "Bill Evans est célèbre pour ses réharmonisations dans lesquelles il :", opts: ["Supprime tous les accords de passage", "Ajoute des emprunts modaux, des extensions et des substitutions subtiles transformant des progressions simples en œuvres sophistiquées", "Joue uniquement en mineur", "Évite les dissonances"], a: 1, fb: "Evans transformait des standards simples (Autumn Leaves, Waltz for Debby) par des emprunts modaux (IVm, bVI), des extensions (9e, b11), des substitutions tritoniques délicates et une conduite de voix impeccable." },
  { q: "Sur 'My Foolish Heart', Evans utilise notamment :", opts: ["Le mode locrien exclusivement", "Des accords parallèles chromatiques et des emprunts au mineur parallèle", "Le jazz blues 12 mesures", "Uniquement des triades"], a: 1, fb: "Evans réharmonise My Foolish Heart avec des accords parallèles chromatiques (impression debussyste) et des emprunts modaux (IVm, bVI) qui assombrissent la couleur. Réharmonisation 'par blocs' caractéristique de son style." },
  { q: "Quelle est la contribution principale de Bill Evans à la réharmonisation jazz ?", opts: ["Inventer la substitution tritonique", "Montrer que les standards peuvent être transformés harmoniquement par des substitutions subtiles sans jamais perturber la mélodie", "Créer la forme blues", "Introduire le mode dorien"], a: 1, fb: "Evans a prouvé qu'une réharmonisation peut être subtile et préserver le 'caractère' d'un standard. Sa version de Waltz for Debby illustre comment réharmoniser pour amplifier — et non masquer — la beauté originale." },
  { q: "Keith Jarrett et Brad Mehldau ont continué la tradition de :", opts: ["Charlie Parker (bebop pur)", "Bill Evans — réharmonisation introspective, emprunts modaux et conduite de voix soignée", "Miles Davis (électrique)", "Oscar Peterson (stride)"], a: 1, fb: "Jarrett et Mehldau héritent directement d'Evans : même attention à la conduite de voix, même usage des emprunts modaux, même capacité à réharmoniser un standard tout en préservant son identité émotionnelle." },
  { q: "Brad Mehldau est connu pour réharmoniser des chansons de :", opts: ["Beethoven", "Radiohead, Nick Drake et d'autres artistes pop/rock", "Vivaldi", "Wagner"], a: 1, fb: "Brad Mehldau réharmonise des chansons pop (Radiohead : Knives Out, Exit Music for a Film ; Nick Drake) avec le langage jazz (extensions, substitutions, emprunts modaux). Réharmonisation cross-genre — mélodie pop, harmonie jazz." },

  // Conduite de voix
  { q: "Pourquoi la conduite de voix est-elle cruciale en réharmonisation ?", opts: ["Car elle détermine le tempo", "Car des changements d'accords brusques créent des sauts peu élégants — la fluidité des voix internes est un critère de qualité", "Car elle supprime les dissonances", "Car elle est imposée par Fux"], a: 1, fb: "Une réharmonisation peut être techniquement correcte (notes compatibles) mais sonner brusquement si les voix internes font de grands sauts. La bonne réharmonisation déplace les voix par demi-tons ou tons — minimum de mouvement, maximum de fluidité." },
  { q: "Quelle règle de conduite de voix s'applique en réharmonisation ?", opts: ["Les voix doivent toujours monter", "Préférer le mouvement conjoint (demi-ton, ton) pour les voix internes", "Ne jamais doubler la fondamentale", "Toujours placer la mélodie à la voix la plus grave"], a: 1, fb: "En réharmonisation : mouvement des voix par petits intervalles (conjoint). G7 → Db7 : les voix internes Si–Ré–Fa trouvent facilement Fa–Lab–Si dans Db7 par mouvement de demi-tons. C'est ce que Evans maîtrisait parfaitement." },
  { q: "Comment la substitution tritonique facilite-t-elle la conduite de voix ?", opts: ["Car elle supprime une voix", "Car les notes de tension (triton) partagées entre V7 et ♭II7 permettent une conduite très fluide", "Car elle n'a que 2 notes", "Car elle est toujours en position fermée"], a: 1, fb: "G7 (G B D F) et Db7 (Db F Ab Cb) partagent Si/Cb et Fa. La substitution tritonique crée un accord voisin avec notes communes — les voix n'ont presque pas à bouger. C'est pourquoi cette substitution semble 'douce' malgré le changement radical de fondamentale." },

  // Applications pratiques
  { q: "Qu'est-ce que réharmoniser 'par blocs' ?", opts: ["Changer tous les accords d'un seul coup", "Modifier un accord à la fois, en laissant le reste intact", "Regrouper les accords par 4", "Jouer tous les accords simultanément"], a: 1, fb: "Réharmoniser par blocs = modifier un accord à la fois dans la progression. Ex. changer uniquement V7 par substitution tritonique, en laissant les autres accords originaux. C'est l'approche la plus sécurisée — on contrôle l'impact de chaque changement." },
  { q: "La 'réharmonisation complète' consiste à :", opts: ["Jouer plus fort", "Remplacer entièrement la grille originale par une nouvelle progression tout en gardant la mélodie", "Transposer dans une autre tonalité", "Jouer sans accords"], a: 1, fb: "La réharmonisation complète reconstruit totalement la grille. La mélodie reste ; les accords en dessous sont entièrement nouveaux. Exemple : Coltrane prend My Favorite Things (mélodie intacte) et lui crée une grille modale totalement différente." },
  { q: "Pourquoi réharmonise-t-on un standard jazz ?", opts: ["Car les accords originaux sont incorrects", "Pour renouveler l'expression artistique, explorer de nouvelles couleurs harmoniques et personnaliser l'interprétation", "Car c'est imposé par les règles du jazz", "Pour faciliter l'improvisation"], a: 1, fb: "La réharmonisation est un outil d'expression. Elle permet à un musicien de 'signer' sa version d'un standard, d'explorer de nouvelles émotions harmoniques, de surprendre l'auditeur familier avec la version originale. C'est de la composition en temps réel." },
  { q: "Sur quel répertoire la réharmonisation est-elle le plus souvent appliquée ?", opts: ["La musique baroque", "Les standards jazz et les mélodies populaires connues", "Les symphonies classiques", "La musique contemporaine uniquement"], a: 1, fb: "On réharmonise surtout les standards jazz (Autumn Leaves, All The Things You Are) et les mélodies populaires. La mélodie connue de l'auditeur crée un contraste avec les accords inattendus — l'effet de surprise est au cœur de la réharmonisation." },

  // Techniques avancées
  { q: "La substitution 'Dm7 – Db7 – Am7' combine :", opts: ["Deux substitutions tritoniques", "Substitution tritonique sur G7 + substitution diatonique I→VI sur CMaj7", "Deux emprunts modaux", "Harmonisation parallèle + emprunt modal"], a: 1, fb: "G7→Db7 (tritonique) et CMaj7→Am7 (diatonique I→VI) combinées donnent Dm7–Db7–Am7. Combiner les techniques multiplie les possibilités de réharmonisation. C'est ainsi que Bill Evans construisait des réharmonisations complexes et subtiles." },
  { q: "Coltrane a réharmonisé 'My Favorite Things' en :", opts: ["La transposant dans toutes les tonalités", "Gardant la mélodie intacte et créant une grille modale (dorien) entièrement nouvelle", "Ajoutant des accords diminués", "Supprimant toutes les cadences"], a: 1, fb: "My Favorite Things chez Coltrane (1960) : mélodie de Rodgers & Hammerstein intacte, grille entièrement modale (ré dorien / mi dorien alternés). La valse 3/4 reste ; les accords sont réinventés. Réharmonisation complète emblématique." },
  { q: "Autumn Leaves peut être réharmonisé en :", opts: ["Changeant uniquement la tonalité", "Substituant les V7 par leurs substituts tritoniques et remplaçant IV par IVm tout en gardant la mélodie", "Le tempo seulement", "La clé seulement"], a: 1, fb: "Autumn Leaves alterne II–V–I majeur et mineur. On peut substituer les V7 par leurs substituts tritoniques (basse chromatique), remplacer FMaj7 par Fm (emprunt modal). La mélodie si connue contraste avec la richesse harmonique ajoutée." },
  { q: "La technique d'harmonisation parallèle a été importée de :", opts: ["Le contrepoint baroque", "Le romantisme allemand", "L'impressionnisme français (Debussy, Ravel)", "Le bebop américain"], a: 2, fb: "Debussy a introduit les accords parallèles dans la musique classique (premières années 1900) — quintes, quartes, accords de 7te parallèles. Les jazzmen américains l'adoptent ensuite. Evans, Jarrett et Mehldau en sont les héritiers jazz." },

  // Révision générale
  { q: "Laquelle des 4 techniques crée le mouvement de basse le plus chromatique ?", opts: ["Substitution diatonique", "Substitution tritonique (♭II7→I = un demi-ton)", "Emprunt modal", "Harmonisation parallèle"], a: 1, fb: "La substitution tritonique crée une résolution par demi-ton descendant — le mouvement de basse le plus court possible. Ex. Db7→CMaj7 : basse Réb→Do, un demi-ton. Ce mouvement chromatique est la caractéristique acoustique la plus reconnaissable de cette technique." },
  { q: "Quelle technique introduit des bémols inattendus dans un contexte majeur ?", opts: ["Substitution tritonique", "Emprunt modal (accords de la gamme mineure parallèle)", "Harmonisation parallèle", "Substitution diatonique"], a: 1, fb: "L'emprunt modal prend des accords de la gamme mineure parallèle — qui contient des bémols (bIII, bVI, bVII). Ces bémols inattendus dans un contexte majeur créent la couleur sombre caractéristique. Ex. en C majeur : Fm introduit Lab, AbMaj7 introduit Lab et Mib." },
  { q: "Quelle technique conserve exactement les mêmes notes de tension que l'accord original ?", opts: ["Emprunt modal", "Harmonisation parallèle", "Substitution tritonique — le triton est partagé", "Substitution diatonique"], a: 2, fb: "La substitution tritonique partage le même triton entre V7 et ♭II7. G7 et Db7 ont tous deux Si et Fa (= Cb) — mêmes notes de tension, rôles inversés. C'est pourquoi la résolution semble 'différente mais familière'." },
  { q: "Une réharmonisation de qualité se reconnaît à :", opts: ["Au nombre d'accords utilisés", "À la fluidité de la conduite de voix, la compatibilité de chaque note mélodique et la cohérence expressive", "Au tempo d'exécution", "À l'absence de dissonances"], a: 1, fb: "Critères : (1) chaque note mélodique est compatible avec le nouvel accord, (2) les voix internes bougent par petits intervalles, (3) l'effet expressif amplifie (ne masque pas) la mélodie. C'est technique ET artistique." },
  { q: "Quel risque majeur existe dans la réharmonisation ?", opts: ["D'utiliser trop peu d'accords", "De sacrifier la fluidité mélodique — si trop radicale, la mélodie semble 'perdue' sur les accords", "De jouer trop doucement", "De jouer les accords trop vite"], a: 1, fb: "Le danger principal : incompatibilité mélodie/accord. Si une note mélodique ne se retrouve pas dans l'accord substitué, la sonorité est agressive et la mélodie flotte dans le vide. La fluidité mélodique prime toujours sur la sophistication harmonique." },
  { q: "Qu'est-ce que le 'bVI emprunt' en C majeur ?", opts: ["Bm7b5", "AbMaj7 (emprunté à C mineur — bVI)", "Am7 (VI diatonique)", "Fm7"], a: 1, fb: "bVI en C majeur = AbMaj7. Cet accord est emprunté à C mineur parallèle (où le 6e degré est bémolisé). AbMaj7 introduit Lab, Mib et Do — couleur très sombre et romantique. Beaucoup utilisé dans le jazz post-bop et la pop (Let It Be inclut cette couleur)." },
  { q: "Dans la substitution diatonique, combien de notes communes idéalement ?", opts: ["Aucune — les accords doivent contraster", "Au moins 2 notes communes (idéalement 3)", "Exactement 1 note commune", "Toutes les notes communes"], a: 1, fb: "Au moins 2 notes communes garantit que la mélodie reste logique sur l'accord substitué. CMaj7–Am7 partagent 3 notes — substitution très naturelle. Moins de notes communes = substitution plus 'risquée' mélodiquement." },
  { q: "Réharmoniser 'Dm7–G7–CMaj7' en 'Dm7–G7–Am7' est une substitution :", opts: ["Tritonique sur G7", "Diatonique I→VI sur CMaj7", "Modale (emprunt de Am7 au mineur)", "Parallèle chromatique"], a: 1, fb: "Am7 remplace CMaj7 par substitution diatonique I→VI. CMaj7 (I) et Am7 (VIm) partagent Do, Mi, Sol — trois notes communes. C'est une résolution déceptive douce : la cadence V7→I devient V7→VIm, moins définitive mais très expressive." },
];

// English translations — add when available; until then falls back to fr


const questionsEn: Question[] = [{ q: "What is reharmonization?", opts: ["Playing more notes", "Replacing the chords of an existing progression with others while keeping the melody", "Changing the melody of a piece", "Transposing to another key"], a: 1, fb: "Reharmonization keeps the melody but replaces the chords. Fundamental condition: each melodic note must be compatible with the new chord (root, third, fifth, seventh, or extension). It is harmonic sculpting." },
{ q: "What is the fundamental condition for a successful reharmonization?", opts: ["Using more complex chords", "The melodic note must be compatible with the new chord", "Always staying in the same key", "Using only tritone substitution"], a: 1, fb: "Each melodic note must belong to the new chord or be an acceptable tension: root, third, fifth, seventh, or extension (9th, 11th, 13th). If the melody sounds wrong over the new chord, the reharmonization fails." },
{ q: "A melodic note is compatible with a chord if it is:", opts: ["Only the root", "Root, third, fifth, seventh, or extension (9th/11th/13th)", "Only the third or the fifth", "Any note"], a: 1, fb: "Compatible notes: root (1), third (3), fifth (5), seventh (7), and extensions (9th, 11th, 13th). If the melody sings E over a reharmonized chord, that chord must contain E in one of these positions." },
{ q: "Reharmonizing a progression means:", opts: ["Changing the tempo", "Replacing all or part of the chords while keeping the melody intact", "Adding new instruments", "Changing the key"], a: 1, fb: "Reharmonizing = changing the chords, keeping the melody. The melody is the fixed element; the chords beneath it can be modified as long as each melodic note remains compatible. It is the art of finding new 'harmonic dressings' for the same tune." },
{ q: "Which pair of chords can substitute for each other in diatonic substitution?", opts: ["I and II", "I and VI", "V and IV", "III and VII"], a: 1, fb: "I and VI share two to three common notes (in C: CMaj7 shares E and G with Am7 — and C). This proximity allows them to be swapped without affecting the melody. II and IV also substitute for each other (Dm7 and FMaj7 share F and A)." },
{ q: "In C major, which chords substitute for each other in diatonic substitution?", opts: ["CMaj7 ↔ Dm7", "CMaj7 ↔ Am7  ·  Dm7 ↔ FMaj7", "G7 ↔ Em7", "Dm7 ↔ G7"], a: 1, fb: "CMaj7 and Am7 share E and G (and C). FMaj7 and Dm7 share F and A. These common notes create sufficient harmonic continuity for the melody to remain logical over the substituted chord." },
{ q: "Why can I and VI substitute for each other?", opts: ["Because they have the same root", "Because they share two to three common notes", "Because they are a tritone apart", "Because they have the same major/minor quality"], a: 1, fb: "In C: CMaj7 = C E G B, Am7 = A C E G. Common notes: C, E, G. The melody sounds right on Am7 if it was singing C, E, or G over CMaj7. More common notes = more natural substitution." },
{ q: "The diatonic substitution 'II ↔ IV' in C major corresponds to:", opts: ["Dm7 ↔ G7", "Dm7 ↔ FMaj7", "Am7 ↔ Em7", "CMaj7 ↔ FMaj7"], a: 1, fb: "IIm7 = Dm7 (D F A C), IV = FMaj7 (F A C E). Common notes: F, A, C. These two chords have a similar subdominant function and can substitute for each other in many contexts." },
{ q: "Replacing CMaj7 with Am7 (I → VI) creates what effect?", opts: ["A stronger resolution", "A slight minor color, softer — a 'gentle deceptive resolution'", "Maximum tension", "A key change"], a: 1, fb: "Am7 shares the notes of CMaj7 but its minor foundation creates a softer, sometimes melancholic color. It is a 'gentle deceptive cadence' — the expected resolution to I arrives but tinged with VIm, less definitive." },
{ q: "The tritone substitute of G7 is:", opts: ["F#7", "Db7", "Ab7", "C#7"], a: 1, fb: "Db7 is located a tritone (6 semitones) above G7. Db7 (Db F Ab Cb) shares the same tritone as G7 (B/Cb and F) — the tension notes are identical but their roles are inverted. The bass descends by a semitone Db→C." },
{ q: "What do G7 and Db7 share, making tritone substitution possible?", opts: ["The root", "The same fifth", "The same tritone — B and F (tension notes)", "The same seventh"], a: 2, fb: "G7 contains B–F (tritone). Db7 contains F–Cb (= B, enharmonic). These two tension notes are identical in both chords but their names are inverted. This sharing is what makes the substitution harmonically coherent." },
{ q: "What effect does tritone substitution create on the bass?", opts: ["A leap of a fifth", "A chromatic descending motion (semitone) toward I", "An ascending motion by semitones", "A static bass"], a: 1, fb: "Db7 → CMaj7: the bass descends by a semitone. Compared to G7 → CMaj7 (descending fifth), this is far more elegant. This chromatic motion is characteristic of bebop jazz and jazz reharmonization." },
{ q: "The tritone substitute of D7 (dominant of GMaj7) is:", opts: ["Eb7", "Ab7", "Bb7", "F#7"], a: 1, fb: "A tritone above D = Ab. Ab7 is the tritone substitute of D7. In the II–V–I of G: Am7–D7–GMaj7 can become Am7–Ab7–GMaj7 (bass A–Ab–G, chromatic descent)." },
{ q: "Why does tritone substitution work harmonically?", opts: ["Because the two chords have the same fifth", "Because V7 and ♭II7 share the same tension notes (the tritone), just with inverted roles", "Because they are in the same scale", "Because the root stays the same"], a: 1, fb: "The tritone of V7 (e.g. B–F of G7) is also the tritone of ♭II7 (F–B of Db7). Both chords create the same resolution tension toward I — same 'fuel,' different root. The bass descends by a semitone instead of a fifth." },
{ q: "In 'Dm7 – Db7 – CMaj7', Db7 replaces which original chord?", opts: ["Dm7 (II)", "G7 (V) by tritone substitution", "Am7 (VI)", "Em7 (III)"], a: 1, fb: "Db7 is the tritone substitute of G7. The original progression Dm7–G7–CMaj7 becomes Dm7–Db7–CMaj7. The bass D–Db–C descends chromatically, making the progression very elegant." },
{ q: "What is modal borrowing in reharmonization?", opts: ["Using a chord from another instrument", "Replacing a chord with its equivalent from the parallel minor scale", "Using the Dorian mode", "Borrowing chords from modal jazz"], a: 1, fb: "Modal borrowing takes a chord from the parallel minor key. In C major, chords are borrowed from C minor: Fm (IVm), Cm (Im), AbMaj7 (bVI), Bb7 (bVII). These chords bring a dark, modal color into a major context." },
{ q: "In C major, 'FMaj7 → Fm' is a borrowing from:", opts: ["The F major scale", "The parallel C minor (IVm = Fm in the parallel minor key)", "The D Dorian scale", "The pentatonic scale"], a: 1, fb: "Fm (F Ab C Eb) is the fourth degree of C minor. It is borrowed from the parallel minor key. Ab (3rd of Fm) creates the dark color. Bill Evans frequently used this 'flatting' of the IV in his standards." },
{ q: "What characteristic note appears when FMaj7 is replaced by Fm in C major?", opts: ["F#", "Ab (bIII of C minor)", "C#", "Bb"], a: 1, fb: "Fm = F Ab C Eb. Ab is the foreign note drawn from C minor. This flatting of the third (A→Ab) characterizes the modal borrowing — an immediately recognizable dark color." },
{ q: "Which chords can be borrowed from the parallel C minor?", opts: ["Only Cm", "Fm (IVm), Cm (Im), AbMaj7 (bVI), Bb7 (bVII), EbMaj7 (bIII)", "Only Fm and Cm", "G7 and D7 only"], a: 1, fb: "The C minor scale provides: Im=Cm, IIm7b5=Dm7b5, bIII=EbMaj7, IVm=Fm, V7=G7, bVI=AbMaj7, bVII=Bb7. All can be borrowed in C major. The most common: Fm, AbMaj7, Bb7 (for their expressive flats)." },
{ q: "Why does modal borrowing create a poignant effect?", opts: ["Because it is easier to play", "Because it introduces unexpected flats that momentarily darken a major color", "Because it eliminates the tritone", "Because it is required by the AABA form"], a: 1, fb: "Modal borrowings (IV→IVm, I→Im) introduce flats drawn from the parallel minor — Ab, Eb, Bb. These unexpected dark colors in a major context create powerful expressive contrast — a hallmark of Bill Evans's sound." },
{ q: "What is parallel harmonization?", opts: ["Playing two melodies simultaneously", "Moving the same chord type chromatically beneath the melody", "Harmonizing in thirds", "Doubling voices at the octave"], a: 1, fb: "Parallel harmonization moves an identical chord type (e.g. Maj7) chromatically or by whole tones following the melody. CMaj7–DbMaj7–DMaj7: same structure, successive roots. An impressionist technique later adopted by jazz." },
{ q: "CMaj7 → DbMaj7 → DMaj7 is an example of:", opts: ["Successive tritone substitutions", "Ascending chromatic parallel harmonization", "Diatonic substitution", "Cycle of fifths"], a: 1, fb: "The same chord type (Maj7) moved chromatically (C→Db→D). The voice leading is mechanical — all voices move by the same interval. The melody floating above creates the harmonic interest." },
{ q: "Which composer is most associated with parallel harmonization?", opts: ["Bach", "Beethoven", "Debussy", "Vivaldi"], a: 2, fb: "Debussy systematized parallel chords in his preludes and nocturnes. French impressionism introduced this technique, which jazz later adopted — notably Bill Evans on My Foolish Heart and Peace Piece." },
{ q: "In parallel harmonization, what creates the harmonic interest?", opts: ["The complexity of the chords", "The melody — the chords move as a block beneath it", "The rapid bass movement", "The tension notes"], a: 1, fb: "Parallel chords are 'neutral' in themselves. It is the unchanging melody that creates the logic and interest. The chromatic succession of chords creates the impressionist effect; the melody carries the listener." },
{ q: "If the melody sings 'E' over a reharmonized chord, which chord is suitable?", opts: ["Fm7 (E absent)", "CMaj7 (E = 3rd)", "Dm7b5 (E absent)", "Bb7 (E absent)"], a: 1, fb: "CMaj7 = C E G B. E is the 3rd of CMaj7 — a chord tone. The melodic note E is perfectly compatible. Rule: the melodic note must be 1, 3, 5, 7, or an extension of the chord." },
{ q: "If the melody sings 'A' over a reharmonized chord, which chord works?", opts: ["Dm7 (A = 5th)", "FMaj7 (A = 3rd)", "Am7 (A = root)", "All of them work"], a: 3, fb: "A is: the 5th of Dm7, the 3rd of FMaj7, the root of Am7. All three chords are compatible with the melodic note A. This is why reharmonization offers so many possibilities — the same note can belong to many chords." },
{ q: "To verify melody/chord compatibility, the note must be:", opts: ["Higher than the bass", "1, 3, 5, 7, or an extension (9th, 11th, 13th) of the chord", "In the same octave as the root", "Below the fifth"], a: 1, fb: "Universal rule: root (1), third (3), fifth (5), seventh (7), or extension (9th, 11th, 13th). Notes outside these categories create unintentional clashes. An unintentional b9 sounds wrong." },
{ q: "Why is 'B natural' problematic over an Fm chord?", opts: ["Because B is too low", "Because B (= augmented 4th / tritone of Fm) is not a natural extension of a minor chord", "Because B is always dissonant", "Because B is too high"], a: 1, fb: "Fm = F Ab C Eb. B is the augmented 4th of Fm — a tritone from the root F. This is not a natural extension. If the melody sings B over Fm, the reharmonization sounds wrong: a different chord must be chosen." },
{ q: "In 'Dm7 – Db7 – CMaj7' with melody G–G–G, is Db7 compatible?", opts: ["No — G is the flatted 4th of Db7, very dissonant", "Yes — G is the fifth of Db7", "No — G is never compatible", "Yes — G is always possible"], a: 0, fb: "Db7 = Db F Ab Cb. G relative to Db: it is the augmented fourth (= tritone). Very dissonant, unnatural. Before finalizing a reharmonization, check each melodic note against each new chord." },
{ q: "Bill Evans is associated with which jazz movement?", opts: ["Bebop of the 1940s", "Cool jazz and post-bop of the 1950s–70s", "Free jazz", "Dixieland"], a: 1, fb: "Bill Evans (1929–1980) is a central figure of cool jazz and post-bop. His work with the Miles Davis Sextet (Kind of Blue, 1959) and his trio defined an introspective, harmonically sophisticated sound." },
{ q: "Bill Evans is famous for his reharmonizations in which he:", opts: ["Removes all passing chords", "Adds modal borrowings, extensions, and subtle substitutions that transform simple progressions into sophisticated works", "Plays only in minor", "Avoids dissonance"], a: 1, fb: "Evans transformed simple standards (Autumn Leaves, Waltz for Debby) through modal borrowings (IVm, bVI), extensions (9th, b11), delicate tritone substitutions, and impeccable voice leading." },
{ q: "On 'My Foolish Heart', Evans notably uses:", opts: ["The Locrian mode exclusively", "Chromatic parallel chords and borrowings from the parallel minor", "The 12-bar jazz blues", "Only triads"], a: 1, fb: "Evans reharmonizes My Foolish Heart with chromatic parallel chords (Debussy-like impression) and modal borrowings (IVm, bVI) that darken the color. 'Block' reharmonization is characteristic of his style." },
{ q: "What is Bill Evans's main contribution to jazz reharmonization?", opts: ["Inventing tritone substitution", "Showing that standards can be harmonically transformed through subtle substitutions without ever disturbing the melody", "Creating the blues form", "Introducing the Dorian mode"], a: 1, fb: "Evans proved that reharmonization can be subtle and preserve the 'character' of a standard. His version of Waltz for Debby illustrates how to reharmonize in order to amplify — not mask — the original beauty." },
{ q: "Keith Jarrett and Brad Mehldau continued the tradition of:", opts: ["Charlie Parker (pure bebop)", "Bill Evans — introspective reharmonization, modal borrowings, and careful voice leading", "Miles Davis (electric)", "Oscar Peterson (stride)"], a: 1, fb: "Jarrett and Mehldau are direct heirs of Evans: the same attention to voice leading, the same use of modal borrowings, the same ability to reharmonize a standard while preserving its emotional identity." },
{ q: "Brad Mehldau is known for reharmonizing songs by:", opts: ["Beethoven", "Radiohead, Nick Drake, and other pop/rock artists", "Vivaldi", "Wagner"], a: 1, fb: "Brad Mehldau reharmonizes pop songs (Radiohead: Knives Out, Exit Music for a Film; Nick Drake) using jazz language (extensions, substitutions, modal borrowings). Cross-genre reharmonization — pop melody, jazz harmony." },
{ q: "Why is voice leading crucial in reharmonization?", opts: ["Because it determines the tempo", "Because abrupt chord changes create inelegant leaps — the smoothness of inner voices is a quality criterion", "Because it eliminates dissonances", "Because it is required by Fux"], a: 1, fb: "A reharmonization can be technically correct (compatible notes) yet sound abrupt if inner voices make large leaps. Good reharmonization moves voices by semitones or whole tones — minimum motion, maximum fluidity." },
{ q: "Which voice leading rule applies in reharmonization?", opts: ["Voices must always ascend", "Prefer stepwise motion (semitone, whole tone) for inner voices", "Never double the root", "Always place the melody in the lowest voice"], a: 1, fb: "In reharmonization: move voices by small intervals (conjunct motion). G7 → Db7: the inner voices B–D–F can easily find F–Ab–B in Db7 by semitone motion. This is what Evans mastered perfectly." },
{ q: "How does tritone substitution facilitate voice leading?", opts: ["Because it removes a voice", "Because the shared tension notes (tritone) between V7 and ♭II7 allow very smooth voice leading", "Because it has only 2 notes", "Because it is always in close position"], a: 1, fb: "G7 (G B D F) and Db7 (Db F Ab Cb) share B/Cb and F. Tritone substitution creates a neighboring chord with common notes — voices barely have to move. This is why this substitution feels 'smooth' despite the radical root change." },
{ q: "What does reharmonizing 'by blocks' mean?", opts: ["Changing all the chords at once", "Modifying one chord at a time, leaving the rest intact", "Grouping chords in sets of 4", "Playing all chords simultaneously"], a: 1, fb: "Reharmonizing by blocks = modifying one chord at a time within the progression. E.g. changing only V7 by tritone substitution while leaving the other chords original. This is the safest approach — you control the impact of each change." },
{ q: "A 'complete reharmonization' consists of:", opts: ["Playing louder", "Entirely replacing the original chord chart with a new progression while keeping the melody", "Transposing to another key", "Playing without chords"], a: 1, fb: "A complete reharmonization totally rebuilds the chord chart. The melody stays; the chords beneath it are entirely new. Example: Coltrane takes My Favorite Things (melody intact) and creates a completely different modal chord grid." },
{ q: "Why does one reharmonize a jazz standard?", opts: ["Because the original chords are incorrect", "To renew artistic expression, explore new harmonic colors, and personalize the interpretation", "Because it is required by jazz rules", "To facilitate improvisation"], a: 1, fb: "Reharmonization is a tool for expression. It allows a musician to 'sign' their version of a standard, explore new harmonic emotions, and surprise listeners familiar with the original version. It is real-time composition." },
{ q: "On which repertoire is reharmonization most often applied?", opts: ["Baroque music", "Jazz standards and well-known popular melodies", "Classical symphonies", "Contemporary music only"], a: 1, fb: "Reharmonization is applied most often to jazz standards (Autumn Leaves, All The Things You Are) and popular melodies. The melody familiar to the listener creates a contrast with the unexpected chords — the element of surprise is at the heart of reharmonization." },
{ q: "The substitution 'Dm7 – Db7 – Am7' combines:", opts: ["Two tritone substitutions", "Tritone substitution on G7 + diatonic substitution I→VI on CMaj7", "Two modal borrowings", "Parallel harmonization + modal borrowing"], a: 1, fb: "G7→Db7 (tritone) and CMaj7→Am7 (diatonic I→VI) combined give Dm7–Db7–Am7. Combining techniques multiplies the reharmonization possibilities. This is how Bill Evans built complex yet subtle reharmonizations." },
{ q: "Coltrane reharmonized 'My Favorite Things' by:", opts: ["Transposing it into every key", "Keeping the melody intact and creating an entirely new modal chord grid (Dorian)", "Adding diminished chords", "Removing all cadences"], a: 1, fb: "My Favorite Things by Coltrane (1960): the Rodgers & Hammerstein melody intact, entirely modal chord grid (D Dorian / E Dorian alternating). The 3/4 waltz remains; the chords are reinvented. An emblematic complete reharmonization." },
{ q: "Autumn Leaves can be reharmonized by:", opts: ["Changing only the key", "Substituting the V7 chords with their tritone substitutes and replacing IV with IVm while keeping the melody", "Changing only the tempo", "Changing only the clef"], a: 1, fb: "Autumn Leaves alternates major and minor II–V–I progressions. The V7 chords can be substituted with their tritone substitutes (chromatic bass), and FMaj7 can be replaced by Fm (modal borrowing). The well-known melody contrasts with the added harmonic richness." },
{ q: "The technique of parallel harmonization was imported from:", opts: ["Baroque counterpoint", "German Romanticism", "French impressionism (Debussy, Ravel)", "American bebop"], a: 2, fb: "Debussy introduced parallel chords into classical music (early 1900s) — parallel fifths, fourths, parallel 7th chords. American jazz musicians later adopted it. Evans, Jarrett, and Mehldau are its jazz heirs." },
{ q: "Which of the 4 techniques creates the most chromatic bass motion?", opts: ["Diatonic substitution", "Tritone substitution (♭II7→I = a semitone)", "Modal borrowing", "Parallel harmonization"], a: 1, fb: "Tritone substitution creates a resolution by descending semitone — the shortest possible bass motion. E.g. Db7→CMaj7: bass Db→C, one semitone. This chromatic motion is the most recognizable acoustic hallmark of this technique." },
{ q: "Which technique introduces unexpected flats in a major context?", opts: ["Tritone substitution", "Modal borrowing (chords from the parallel minor scale)", "Parallel harmonization", "Diatonic substitution"], a: 1, fb: "Modal borrowing takes chords from the parallel minor scale — which contains flats (bIII, bVI, bVII). These unexpected flats in a major context create the characteristic dark color. E.g. in C major: Fm introduces Ab, AbMaj7 introduces Ab and Eb." },
{ q: "Which technique retains exactly the same tension notes as the original chord?", opts: ["Modal borrowing", "Parallel harmonization", "Tritone substitution — the tritone is shared", "Diatonic substitution"], a: 2, fb: "Tritone substitution shares the same tritone between V7 and ♭II7. G7 and Db7 both contain B and F (= Cb) — same tension notes, inverted roles. This is why the resolution feels 'different yet familiar'." },
{ q: "A quality reharmonization is recognized by:", opts: ["The number of chords used", "The smoothness of the voice leading, the compatibility of each melodic note, and the expressive coherence", "The performance tempo", "The absence of dissonances"], a: 1, fb: "Criteria: (1) each melodic note is compatible with the new chord, (2) inner voices move by small intervals, (3) the expressive effect amplifies (rather than masks) the melody. It is both technical and artistic." },
{ q: "What is the main risk in reharmonization?", opts: ["Using too few chords", "Sacrificing melodic fluidity — if too radical, the melody seems 'lost' over the chords", "Playing too softly", "Playing the chords too fast"], a: 1, fb: "The main danger: melody/chord incompatibility. If a melodic note is not found in the substituted chord, the sound is harsh and the melody floats in a void. Melodic fluidity always takes precedence over harmonic sophistication." },
{ q: "What is the 'bVI borrowing' in C major?", opts: ["Bm7b5", "AbMaj7 (borrowed from C minor — bVI)", "Am7 (diatonic VI)", "Fm7"], a: 1, fb: "bVI in C major = AbMaj7. This chord is borrowed from the parallel C minor (where the 6th degree is flatted). AbMaj7 introduces Ab, Eb, and C — a very dark and romantic color. Widely used in post-bop jazz and pop (Let It Be includes this color)." },
{ q: "In diatonic substitution, how many common notes are ideal?", opts: ["None — the chords must contrast", "At least 2 common notes (ideally 3)", "Exactly 1 common note", "All notes in common"], a: 1, fb: "At least 2 common notes ensures the melody remains logical over the substituted chord. CMaj7–Am7 share 3 notes — a very natural substitution. Fewer common notes = a more 'risky' substitution melodically." },
{ q: "Reharmonizing 'Dm7–G7–CMaj7' as 'Dm7–G7–Am7' is a:", opts: ["Tritone substitution on G7", "Diatonic substitution I→VI on CMaj7", "Modal borrowing (Am7 borrowed from the minor)", "Chromatic parallel substitution"], a: 1, fb: "Am7 replaces CMaj7 through diatonic substitution I→VI. CMaj7 (I) and Am7 (VIm) share C, E, G — three common notes. It is a gentle deceptive resolution: the cadence V7→I becomes V7→VIm, less definitive but very expressive." }
];

const questionsDe: Question[] = [{ q: "Was ist Reharmonisierung?", opts: ["Mehr Noten spielen", "Die Akkorde einer bestehenden Progression ersetzen und dabei die Melodie beibehalten", "Die Melodie eines Stücks verändern", "In eine andere Tonart transponieren"], a: 1, fb: "Reharmonisierung behält die Melodie bei, ersetzt aber die Akkorde. Grundbedingung: Jede Melodienote muss mit dem neuen Akkord kompatibel sein (Grundton, Terz, Quinte, Septime oder Extension). Es ist harmonisches Gestalten." },
{ q: "Was ist die Grundbedingung einer gelungenen Reharmonisierung?", opts: ["Komplexere Akkorde verwenden", "Die Melodienote muss mit dem neuen Akkord kompatibel sein", "Immer in der gleichen Tonart bleiben", "Nur Tritonussubstitution verwenden"], a: 1, fb: "Jede Melodienote muss dem neuen Akkord angehören oder eine akzeptable Spannung darstellen: Grundton, Terz, Quinte, Septime oder Extension (9., 11., 13.). Klingt die Melodie auf dem neuen Akkord falsch, scheitert die Reharmonisierung." },
{ q: "Eine Melodienote ist mit einem Akkord kompatibel, wenn sie ist:", opts: ["Ausschließlich der Grundton", "Grundton, Terz, Quinte, Septime oder Extension (9./11./13.)", "Nur Terz oder Quinte", "Irgendeine Note"], a: 1, fb: "Kompatible Noten: Grundton (1), Terz (3), Quinte (5), Septime (7) und Extensions (9., 11., 13.). Singt die Melodie E über einem reharmonisierten Akkord, muss dieser Akkord E in einer dieser Positionen enthalten." },
{ q: "Eine Progression zu reharmonisieren bedeutet:", opts: ["Das Tempo zu ändern", "Alle oder einige Akkorde zu ersetzen und dabei die Melodie unverändert zu lassen", "Neue Instrumente hinzuzufügen", "Die Tonart zu wechseln"], a: 1, fb: "Reharmonisieren = Akkorde ändern, Melodie behalten. Die Melodie ist das feste Element; die Akkorde darunter sind veränderbar, solange jede Melodienote kompatibel bleibt. Es ist die Kunst, neue 'harmonische Gewänder' für eine bekannte Melodie zu finden." },
{ q: "Welches Akkordpaar kann bei der diatonischen Substitution ausgetauscht werden?", opts: ["I und II", "I und VI", "V und IV", "III und VII"], a: 1, fb: "I und VI teilen zwei bis drei gemeinsame Noten (in C: CMaj7 teilt E und G mit Am7 — sowie C). Diese Nähe erlaubt den Austausch, ohne die Melodie zu beeinträchtigen. II und IV können ebenfalls substituiert werden (Dm7 und FMaj7 teilen F und A)." },
{ q: "In C-Dur, welche Akkorde werden bei der diatonischen Substitution ausgetauscht?", opts: ["CMaj7 ↔ Dm7", "CMaj7 ↔ Am7  ·  Dm7 ↔ FMaj7", "G7 ↔ Em7", "Dm7 ↔ G7"], a: 1, fb: "CMaj7 und Am7 teilen E und G (sowie C). FMaj7 und Dm7 teilen F und A. Diese gemeinsamen Noten schaffen genug harmonische Kontinuität, damit die Melodie auf dem substituierten Akkord logisch klingt." },
{ q: "Warum können I und VI substituiert werden?", opts: ["Weil sie denselben Grundton haben", "Weil sie zwei bis drei gemeinsame Noten teilen", "Weil sie einen Tritonusabstand haben", "Weil sie dieselbe Dur/Moll-Qualität haben"], a: 1, fb: "In C: CMaj7 = C E G B, Am7 = A C E G. Gemeinsame Noten: C, E, G. Die Melodie klingt auf Am7 richtig, wenn sie C, E oder G auf CMaj7 sang. Mehr gemeinsame Noten = natürlichere Substitution." },
{ q: "Die diatonische Substitution 'II ↔ IV' in C-Dur entspricht:", opts: ["Dm7 ↔ G7", "Dm7 ↔ FMaj7", "Am7 ↔ Em7", "CMaj7 ↔ FMaj7"], a: 1, fb: "IIm7 = Dm7 (D F A C), IV = FMaj7 (F A C E). Gemeinsame Noten: F, A, C. Diese beiden Akkorde haben eine ähnliche Subdominantfunktion und können in vielen Kontexten substituiert werden." },
{ q: "CMaj7 durch Am7 zu ersetzen (I → VI) erzeugt welchen Effekt?", opts: ["Eine stärkere Auflösung", "Eine leicht mollhafte, weichere Farbe — 'weiche Trugkadenz'", "Maximale Spannung", "Einen Tonartenwechsel"], a: 1, fb: "Am7 teilt die Noten von CMaj7, aber sein Moll-Fundament erzeugt eine weichere, manchmal melancholische Färbung. Es ist eine 'weiche Trugkadenz' — die erwartete Auflösung auf I kommt, aber eingefärbt durch VIm, weniger abschließend." },
{ q: "Der Tritonussubstitut von G7 ist:", opts: ["F#7", "Db7", "Ab7", "C#7"], a: 1, fb: "Db7 liegt einen Tritonus (6 Halbtöne) über G7. Db7 (Db F Ab Cb) teilt denselben Tritonus wie G7 (B/Cb und F) — die Spannungsnoten sind identisch, aber ihre Rollen sind vertauscht. Der Bass steigt einen Halbton ab: Db→C." },
{ q: "Was teilen G7 und Db7, das die Tritonussubstitution ermöglicht?", opts: ["Den Grundton", "Dieselbe Quinte", "Denselben Tritonus — B und F (Spannungsnoten)", "Dieselbe Septime"], a: 2, fb: "G7 enthält B–F (Tritonus). Db7 enthält F–Cb (= B, enharmonisch). Diese beiden Spannungsnoten sind in beiden Akkorden identisch, aber ihre Namen sind vertauscht. Dieses Teilen macht die Substitution harmonisch kohärent." },
{ q: "Welchen Effekt erzeugt die Tritonussubstitution im Bass?", opts: ["Einen Quintsprung", "Eine chromatische Abwärtsbewegung (Halbton) zu I", "Eine aufsteigende Haltonbewegung", "Einen festen Bass"], a: 1, fb: "Db7 → CMaj7: Der Bass steigt einen Halbton ab. Verglichen mit G7 → CMaj7 (absteigende Quinte) ist das wesentlich eleganter. Diese chromatische Bewegung ist charakteristisch für Bebop-Jazz und Jazz-Reharmonisierung." },
{ q: "Der Tritonussubstitut von D7 (Dominante von GMaj7) ist:", opts: ["Eb7", "Ab7", "Bb7", "F#7"], a: 1, fb: "Ein Tritonus über D (Re) = Ab (As). Ab7 ist der Tritonussubstitut von D7. In II–V–I von G: Am7–D7–GMaj7 kann zu Am7–Ab7–GMaj7 werden (Bass A–Ab–G, chromatische Abstieg)." },
{ q: "Warum funktioniert die Tritonussubstitution harmonisch?", opts: ["Weil beide Akkorde dieselbe Quinte haben", "Weil V7 und ♭II7 dieselben Spannungsnoten (den Tritonus) teilen, nur mit vertauschten Rollen", "Weil sie in derselben Tonleiter sind", "Weil der Grundton gleich bleibt"], a: 1, fb: "Der Tritonus von V7 (z.B. B–F von G7) ist auch der Tritonus von ♭II7 (F–B von Db7). Beide Akkorde erzeugen dieselbe Auflösungsspannung zu I — gleicher 'Treibstoff', unterschiedlicher Grundton. Der Bass steigt einen Halbton statt einer Quinte ab." },
{ q: "In 'Dm7 – Db7 – CMaj7', welchen Originalakkord ersetzt Db7?", opts: ["Dm7 (II)", "G7 (V) durch Tritonussubstitution", "Am7 (VI)", "Em7 (III)"], a: 1, fb: "Db7 ist der Tritonussubstitut von G7. Die Originalprogression Dm7–G7–CMaj7 wird zu Dm7–Db7–CMaj7. Der Bass D–Db–C steigt chromatisch ab, was die Progression sehr elegant macht." },
{ q: "Was ist eine modale Entlehnung in der Reharmonisierung?", opts: ["Einen Akkord von einem anderen Instrument verwenden", "Einen Akkord durch sein Gegenstück aus der parallelen Molltonleiter ersetzen", "Den dorischen Modus verwenden", "Akkorde aus dem modalen Jazz entlehnen"], a: 1, fb: "Modale Entlehnung übernimmt einen Akkord aus der gleichnamigen Molltonart. In C-Dur entlehnt man aus C-Moll: Fm (IVm), Cm (Im), AbMaj7 (bVI), Bb7 (bVII). Diese Akkorde bringen eine dunkle, modale Färbung in einen Dur-Kontext." },
{ q: "In C-Dur ist 'FMaj7 → Fm' eine Entlehnung aus:", opts: ["Der F-Dur-Tonleiter", "Der parallelen C-Moll-Tonart (IVm = Fm in der gleichnamigen Molltonleiter)", "Der Re-dorischen Tonleiter", "Der Pentatonik"], a: 1, fb: "Fm (F Ab C Eb) ist die IV. Stufe von C-Moll. Es wird aus der gleichnamigen Molltonart entlehnt. Ab (3. von Fm) erzeugt die dunkle Färbung. Bill Evans nutzte häufig diese 'Mollisierung' der IV. Stufe bei Standards." },
{ q: "Welche charakteristische Note erscheint, wenn FMaj7 durch Fm in C-Dur ersetzt wird?", opts: ["F#", "Ab (bIII von C-Moll)", "C#", "Bb"], a: 1, fb: "Fm = F Ab C Eb. Das Ab ist die aus C-Moll stammende Fremdnote. Diese Mollisierung der Terz (A→Ab) charakterisiert die modale Entlehnung — sofort erkennbare dunkle Färbung." },
{ q: "Welche Akkorde können aus der parallelen C-Moll-Tonart entlehnt werden?", opts: ["Nur Cm", "Fm (IVm), Cm (Im), AbMaj7 (bVI), Bb7 (bVII), EbMaj7 (bIII)", "Nur Fm und Cm", "Nur G7 und D7"], a: 1, fb: "Die C-Moll-Tonleiter liefert: Im=Cm, IIm7b5=Dm7b5, bIII=EbMaj7, IVm=Fm, V7=G7, bVI=AbMaj7, bVII=Bb7. Alle können in C-Dur entlehnt werden. Die gebräuchlichsten: Fm, AbMaj7, Bb7 (wegen ihrer ausdrucksstarken Vorzeichen)." },
{ q: "Warum erzeugt modale Entlehnung einen ergreifenden Effekt?", opts: ["Weil es leichter zu spielen ist", "Weil es unerwartete Vorzeichen einführt, die eine Durfarbe momentan verdunkeln", "Weil es den Tritonus aufhebt", "Weil es durch die AABA-Form vorgeschrieben ist"], a: 1, fb: "Modale Entlehnungen (IV→IVm, I→Im) führen Vorzeichen aus der parallelen Molltonart ein — Ab, Eb, Bb. Diese unerwarteten dunklen Färbungen in einem Dur-Kontext schaffen einen ausdrucksstarken Kontrast — Markenzeichen des Bill Evans-Sounds." },
{ q: "Was ist parallele Harmonisierung?", opts: ["Zwei Melodien gleichzeitig spielen", "Denselben Akkordtyp chromatisch unter der Melodie verschieben", "In Terzen harmonisieren", "Stimmen in der Oktave verdoppeln"], a: 1, fb: "Parallele Harmonisierung verschiebt einen identischen Akkordtyp (z.B. Maj7) chromatisch oder in Ganztonschritten entlang der Melodie. CMaj7–DbMaj7–DMaj7: gleiche Struktur, aufeinanderfolgende Grundtöne. Impressionistische Technik, vom Jazz übernommen." },
{ q: "CMaj7 → DbMaj7 → DMaj7 ist ein Beispiel für:", opts: ["Aufeinanderfolgende Tritonussubstitutionen", "Chromatisch aufsteigende parallele Harmonisierung", "Diatonische Substitution", "Quintenzirkel"], a: 1, fb: "Gleicher Akkordtyp (Maj7) chromatisch verschoben (C→Db→D). Die Stimmführung ist mechanisch — alle Stimmen bewegen sich um dasselbe Intervall. Die darüber schwebende Melodie erzeugt das harmonische Interesse." },
{ q: "Welcher Komponist wird vor allem mit paralleler Harmonisierung verbunden?", opts: ["Bach", "Beethoven", "Debussy", "Vivaldi"], a: 2, fb: "Debussy hat parallele Akkorde in seinen Préludes und Nocturnes systematisch eingesetzt. Der französische Impressionismus hat diese Technik eingeführt, die der Jazz übernahm — insbesondere Bill Evans in My Foolish Heart und Peace Piece." },
{ q: "Was erzeugt bei der parallelen Harmonisierung das harmonische Interesse?", opts: ["Die Komplexität der Akkorde", "Die Melodie — die Akkorde verschieben sich als Block darunter", "Die schnelle Bassbewegung", "Die Spannungsnoten"], a: 1, fb: "Parallele Akkorde sind für sich genommen 'neutral'. Die unveränderliche Melodie schafft die Logik und das Interesse. Die chromatische Abfolge der Akkorde erzeugt den impressionistischen Effekt; die Melodie trägt den Hörer." },
{ q: "Wenn die Melodie 'E' über einem reharmonisierten Akkord singt, welcher Akkord passt?", opts: ["Fm7 (E fehlt)", "CMaj7 (E = Terz)", "Dm7b5 (E fehlt)", "Bb7 (E fehlt)"], a: 1, fb: "CMaj7 = C E G B. E ist die Terz von CMaj7 — eine Akkordnote. Die Melodienote E ist vollständig kompatibel. Regel: Die Melodienote muss 1, 3, 5, 7 oder Extension des Akkords sein." },
{ q: "Wenn die Melodie 'A' über einem reharmonisierten Akkord singt, welcher passt?", opts: ["Dm7 (A = Quinte)", "FMaj7 (A = Terz)", "Am7 (A = Grundton)", "Alle funktionieren"], a: 3, fb: "A ist: Quinte von Dm7, Terz von FMaj7, Grundton von Am7. Alle drei Akkorde sind mit der Melodienote A kompatibel. Deshalb bietet Reharmonisierung so viele Möglichkeiten — dieselbe Note kann vielen Akkorden angehören." },
{ q: "Um die Kompatibilität von Melodie und Akkord zu prüfen, muss die Note sein:", opts: ["Höher als der Bass", "1, 3, 5, 7 oder Extension (9., 11., 13.) des Akkords", "In derselben Oktave wie der Grundton", "Tiefer als die Quinte"], a: 1, fb: "Universelle Regel: Grundton (1), Terz (3), Quinte (5), Septime (7) oder Extension (9., 11., 13.). Noten außerhalb dieser Kategorien erzeugen unbeabsichtigte Reibungen. Eine unbeabsichtigte b9 klingt falsch." },
{ q: "Warum ist B (H) auf einem Fm-Akkord problematisch?", opts: ["Weil B zu tief ist", "Weil B (= übermäßige Quarte / Tritonus von Fm) keine natürliche Extension eines Mollakkords ist", "Weil B immer dissonant ist", "Weil B zu hoch ist"], a: 1, fb: "Fm = F Ab C Eb. B ist die übermäßige Quarte von Fm — ein Tritonus zum Grundton F. Das ist keine natürliche Extension. Singt die Melodie B über Fm, klingt die Reharmonisierung falsch: Ein anderer Akkord muss gewählt werden." },
{ q: "In 'Dm7 – Db7 – CMaj7' mit der Melodie G–G–G, ist Db7 kompatibel?", opts: ["Nein — G ist die verminderte Quarte von Db7, sehr dissonant", "Ja — G ist die Quinte von Db7", "Nein — G ist nie kompatibel", "Ja — G ist immer möglich"], a: 0, fb: "Db7 = Db F Ab Cb. G in Bezug auf Db: das ist die übermäßige Quarte (= Tritonus). Sehr dissonant, nicht natürlich. Vor der Bestätigung einer Reharmonisierung muss jede Melodienote auf jedem neuen Akkord geprüft werden." },
{ q: "Bill Evans wird mit welcher Strömung des Jazz verbunden?", opts: ["Bebop der 1940er Jahre", "Cool Jazz und Post-Bop der 1950er–70er Jahre", "Free Jazz", "Dixieland"], a: 1, fb: "Bill Evans (1929–1980) ist eine zentrale Figur des Cool Jazz und Post-Bop. Sein Spiel mit dem Miles Davis Sextet (Kind of Blue, 1959) und sein Trio definierten einen introspektiven, harmonisch ausgefeilten Sound." },
{ q: "Bill Evans ist bekannt für seine Reharmonisierungen, in denen er:", opts: ["Alle Durchgangsakkorde weglässt", "Modale Entlehnungen, Extensions und subtile Substitutionen hinzufügt und einfache Progressionen in ausgefeilte Werke verwandelt", "Nur in Moll spielt", "Dissonanzen vermeidet"], a: 1, fb: "Evans verwandelte einfache Standards (Autumn Leaves, Waltz for Debby) durch modale Entlehnungen (IVm, bVI), Extensions (9., b11), subtile Tritonussubstitutionen und eine makellose Stimmführung." },
{ q: "Auf 'My Foolish Heart' verwendet Evans insbesondere:", opts: ["Ausschließlich den lokriischen Modus", "Chromatisch parallele Akkorde und Entlehnungen aus der parallelen Molltonart", "Das 12-taktige Jazz-Blues-Schema", "Nur Dreiklänge"], a: 1, fb: "Evans reharmonisiert My Foolish Heart mit chromatisch parallelen Akkorden (debussyistischer Eindruck) und modalen Entlehnungen (IVm, bVI), die die Färbung verdunkeln. Für seinen Stil charakteristische Blockreharmonisierung." },
{ q: "Was ist der Hauptbeitrag von Bill Evans zur Jazz-Reharmonisierung?", opts: ["Die Tritonussubstitution erfunden zu haben", "Gezeigt zu haben, dass Standards durch subtile Substitutionen harmonisch verwandelt werden können, ohne die Melodie je zu stören", "Die Bluesform geschaffen zu haben", "Den dorischen Modus eingeführt zu haben"], a: 1, fb: "Evans bewies, dass Reharmonisierung subtil sein und den 'Charakter' eines Standards bewahren kann. Seine Version von Waltz for Debby zeigt, wie man reharmonisiert, um die ursprüngliche Schönheit zu verstärken — und nicht zu verdecken." },
{ q: "Keith Jarrett und Brad Mehldau haben die Tradition von wem weitergeführt?", opts: ["Charlie Parker (reiner Bebop)", "Bill Evans — introspektive Reharmonisierung, modale Entlehnungen und sorgfältige Stimmführung", "Miles Davis (elektrisch)", "Oscar Peterson (Stride)"], a: 1, fb: "Jarrett und Mehldau erben direkt von Evans: dieselbe Sorgfalt in der Stimmführung, denselben Umgang mit modalen Entlehnungen, dieselbe Fähigkeit, einen Standard zu reharmonisieren und dabei seine emotionale Identität zu bewahren." },
{ q: "Brad Mehldau ist bekannt dafür, Songs von wem zu reharmonisieren?", opts: ["Beethoven", "Radiohead, Nick Drake und anderen Pop/Rock-Künstlern", "Vivaldi", "Wagner"], a: 1, fb: "Brad Mehldau reharmonisiert Pop-Songs (Radiohead: Knives Out, Exit Music for a Film; Nick Drake) mit der Jazz-Sprache (Extensions, Substitutionen, modale Entlehnungen). Genreübergreifende Reharmonisierung — Pop-Melodie, Jazz-Harmonie." },
{ q: "Warum ist Stimmführung bei der Reharmonisierung entscheidend?", opts: ["Weil sie das Tempo bestimmt", "Weil abrupte Akkordwechsel unelegante Sprünge erzeugen — die Flüssigkeit der Innenstimmen ist ein Qualitätsmerkmal", "Weil sie Dissonanzen beseitigt", "Weil sie von Fux vorgeschrieben ist"], a: 1, fb: "Eine Reharmonisierung kann technisch korrekt (kompatible Noten) sein, aber abrupt klingen, wenn die Innenstimmen große Sprünge machen. Gute Reharmonisierung bewegt die Stimmen in Halb- oder Ganztonschritten — minimale Bewegung, maximale Flüssigkeit." },
{ q: "Welche Stimmführungsregel gilt bei der Reharmonisierung?", opts: ["Die Stimmen müssen immer aufsteigen", "Stufenweise Bewegung (Halbton, Ganzton) für die Innenstimmen bevorzugen", "Den Grundton nie verdoppeln", "Die Melodie immer in die tiefste Stimme legen"], a: 1, fb: "Bei der Reharmonisierung: Stimmenbewegung in kleinen Intervallen (stufenweise). G7 → Db7: Die Innenstimmen B–D–F finden in Db7 leicht F–Ab–B durch Halbtonbewegung. Das beherrschte Evans meisterhaft." },
{ q: "Wie erleichtert die Tritonussubstitution die Stimmführung?", opts: ["Weil sie eine Stimme weglässt", "Weil die gemeinsamen Spannungsnoten (Tritonus) zwischen V7 und ♭II7 eine sehr fließende Stimmführung ermöglichen", "Weil sie nur 2 Noten hat", "Weil sie immer in enger Lage ist"], a: 1, fb: "G7 (G B D F) und Db7 (Db F Ab Cb) teilen B/Cb und F. Die Tritonussubstitution schafft einen benachbarten Akkord mit gemeinsamen Noten — die Stimmen müssen sich kaum bewegen. Deshalb wirkt diese Substitution 'sanft' trotz des radikalen Grundtonwechsels." },
{ q: "Was bedeutet 'blockweise' Reharmonisierung?", opts: ["Alle Akkorde auf einmal ändern", "Einen Akkord nach dem anderen ändern und den Rest unverändert lassen", "Akkorde in Vierergruppen zusammenfassen", "Alle Akkorde gleichzeitig spielen"], a: 1, fb: "Blockweise Reharmonisierung = einen Akkord nach dem anderen in der Progression ändern. Z.B. nur V7 durch Tritonussubstitution ersetzen und die übrigen Originalakkorde beibehalten. Das ist der sicherste Ansatz — man kontrolliert die Auswirkung jeder Änderung." },
{ q: "Die 'vollständige Reharmonisierung' besteht darin:", opts: ["Lauter zu spielen", "Die gesamte Originalharmonik durch eine neue Progression zu ersetzen und dabei die Melodie beizubehalten", "In eine andere Tonart zu transponieren", "Ohne Akkorde zu spielen"], a: 1, fb: "Die vollständige Reharmonisierung baut das gesamte Akkordgerüst neu auf. Die Melodie bleibt; die Akkorde darunter sind völlig neu. Beispiel: Coltrane nimmt My Favorite Things (Melodie unverändert) und gibt ihm ein völlig neues modales Akkordgerüst." },
{ q: "Warum reharmonisiert man einen Jazz-Standard?", opts: ["Weil die Originalakkorde falsch sind", "Um den künstlerischen Ausdruck zu erneuern, neue harmonische Farben zu erkunden und die Interpretation zu personalisieren", "Weil es von den Jazz-Regeln verlangt wird", "Um die Improvisation zu erleichtern"], a: 1, fb: "Reharmonisierung ist ein Ausdrucksmittel. Sie erlaubt einem Musiker, seine Version eines Standards zu 'signieren', neue harmonische Emotionen zu erkunden und den mit der Originalversion vertrauten Hörer zu überraschen. Es ist Komposition in Echtzeit." },
{ q: "Auf welchem Repertoire wird Reharmonisierung am häufigsten angewendet?", opts: ["Barockmusik", "Jazz-Standards und bekannte Volksmelodien", "Klassische Sinfonien", "Ausschließlich zeitgenössische Musik"], a: 1, fb: "Reharmonisiert werden vor allem Jazz-Standards (Autumn Leaves, All The Things You Are) und bekannte Melodien. Die dem Hörer bekannte Melodie bildet einen Kontrast zu den unerwarteten Akkorden — der Überraschungseffekt ist das Herzstück der Reharmonisierung." },
{ q: "Die Substitution 'Dm7 – Db7 – Am7' kombiniert:", opts: ["Zwei Tritonussubstitutionen", "Tritonussubstitution auf G7 + diatonische Substitution I→VI auf CMaj7", "Zwei modale Entlehnungen", "Parallele Harmonisierung + modale Entlehnung"], a: 1, fb: "G7→Db7 (Tritonus) und CMaj7→Am7 (diatonisch I→VI) kombiniert ergeben Dm7–Db7–Am7. Die Kombination von Techniken vervielfacht die Reharmonisierungsmöglichkeiten. So baute Bill Evans komplexe und subtile Reharmonisierungen auf." },
{ q: "Coltrane reharmonisierte 'My Favorite Things', indem er:", opts: ["Es in alle Tonarten transponierte", "Die Melodie unverändert ließ und ein völlig neues modales Akkordgerüst (dorisch) schuf", "Verminderte Akkorde hinzufügte", "Alle Kadenzen entfernte"], a: 1, fb: "My Favorite Things bei Coltrane (1960): Melodie von Rodgers & Hammerstein unverändert, Akkordgerüst vollständig modal (alternierend Re dorisch / Mi dorisch). Der 3/4-Walzer bleibt; die Akkorde sind neu erfunden. Emblematische vollständige Reharmonisierung." },
{ q: "Autumn Leaves kann reharmonisiert werden, indem man:", opts: ["Nur die Tonart ändert", "Die V7-Akkorde durch ihre Tritonussubstitute ersetzt und IV durch IVm austauscht, dabei die Melodie behält", "Nur das Tempo ändert", "Nur den Schlüssel ändert"], a: 1, fb: "Autumn Leaves wechselt zwischen Dur- und Moll-II–V–I. Man kann die V7-Akkorde durch ihre Tritonussubstitute ersetzen (chromatischer Bass), FMaj7 durch Fm (modale Entlehnung) austauschen. Die so bekannte Melodie kontrastiert mit der hinzugefügten harmonischen Fülle." },
{ q: "Die Technik der parallelen Harmonisierung wurde übernommen aus:", opts: ["Dem Barocken Kontrapunkt", "Der deutschen Romantik", "Dem französischen Impressionismus (Debussy, Ravel)", "Dem amerikanischen Bebop"], a: 2, fb: "Debussy führte parallele Akkorde in die klassische Musik ein (Anfang des 20. Jahrhunderts) — Quinten, Quarten, parallele Septakkorde. Amerikanische Jazzmusiker übernahmen sie anschließend. Evans, Jarrett und Mehldau sind ihre Jazz-Erben." },
{ q: "Welche der 4 Techniken erzeugt die chromatischste Bassbewegung?", opts: ["Diatonische Substitution", "Tritonussubstitution (♭II7→I = ein Halbton)", "Modale Entlehnung", "Parallele Harmonisierung"], a: 1, fb: "Die Tritonussubstitution schafft eine Auflösung durch einen absteigenden Halbton — die kleinstmögliche Bassbewegung. Z.B. Db7→CMaj7: Bass Db→C, ein Halbton. Diese chromatische Bewegung ist das erkennbarste akustische Merkmal dieser Technik." },
  { q: "Welche Technik führt unerwartete Erniedrigungszeichen in einem Dur-Kontext ein?", opts: ["Tritonussubstitution", "Modaler Entleihung (Akkorde der parallelen Molltonleiter)", "Parallele Harmonisierung", "Diatonische Substitution"], a: 1, fb: "Die modale Entlehnung entnimmt Akkorde der parallelen Molltonleiter — die Erniedrigungszeichen enthält (bIII, bVI, bVII). Diese unerwarteten Erniedrigungszeichen in einem Dur-Kontext erzeugen die charakteristische dunkle Farbe. Z.B. in C-Dur: Fm führt As ein, AbMaj7 führt As und Es ein." },
  { q: "Welche Technik bewahrt exakt dieselben Spannungstöne wie der Originalakkord?", opts: ["Modale Entlehnung", "Parallele Harmonisierung", "Tritonussubstitution — der Tritonus wird geteilt", "Diatonische Substitution"], a: 2, fb: "Die Tritonussubstitution teilt denselben Tritonus zwischen V7 und ♭II7. G7 und Db7 haben beide H und F (= Ces) — gleiche Spannungstöne, vertauschte Rollen. Deshalb klingt die Auflösung 'anders aber vertraut'." },
  { q: "Eine qualitativ hochwertige Reharmonisierung erkennt man an:", opts: ["Der Anzahl der verwendeten Akkorde", "Der Flüssigkeit der Stimmführung, Kompatibilität jeder Melodienote und expressiver Kohärenz", "Dem Ausführungstempo", "Der Abwesenheit von Dissonanzen"], a: 1, fb: "Kriterien: (1) jede Melodienote ist mit dem neuen Akkord kompatibel, (2) die Innenstimmen bewegen sich in kleinen Intervallen, (3) die expressive Wirkung verstärkt (verschleiert nicht) die Melodie. Es ist technisch UND künstlerisch." },
  { q: "Welches Hauptrisiko besteht bei der Reharmonisierung?", opts: ["Zu wenige Akkorde zu verwenden", "Die melodische Flüssigkeit zu opfern — wenn zu radikal, scheint die Melodie auf den Akkorden 'verloren'", "Zu leise zu spielen", "Die Akkorde zu schnell zu spielen"], a: 1, fb: "Die Hauptgefahr: Melodie/Akkord-Inkompatibilität. Wenn eine Melodienote im substituierten Akkord nicht vorkommt, ist der Klang aggressiv und die Melodie schwebt im Nichts. Melodische Flüssigkeit geht immer vor harmonischer Raffinesse." },
  { q: "Was ist der 'bVI-Entleih' in C-Dur?", opts: ["Bm7b5", "AbMaj7 (aus C-Moll entliehen — bVI)", "Am7 (diatonische VI)", "Fm7"], a: 1, fb: "bVI in C-Dur = AbMaj7. Dieser Akkord ist aus dem parallelen C-Moll entliehen (wo die 6. Stufe erniedrigt ist). AbMaj7 führt As, Es und C ein — sehr dunkle und romantische Farbe. Viel verwendet im Post-Bop-Jazz und Pop." },
  { q: "Bei der diatonischen Substitution, wie viele gemeinsame Töne idealerweise?", opts: ["Keine — die Akkorde müssen kontrastieren", "Mindestens 2 gemeinsame Töne (idealerweise 3)", "Genau 1 gemeinsamer Ton", "Alle Töne gemeinsam"], a: 1, fb: "Mindestens 2 gemeinsame Töne garantiert, dass die Melodie auf dem substituierten Akkord logisch bleibt. CMaj7–Am7 teilen 3 Töne — sehr natürliche Substitution. Weniger gemeinsame Töne = melodisch 'riskantere' Substitution." },
  { q: "'Dm7–G7–CMaj7' zu 'Dm7–G7–Am7' zu reharmonisieren ist eine Substitution:", opts: ["Tritonisch auf G7", "Diatonisch I→VI auf CMaj7", "Modal (Am7 aus dem Moll entliehen)", "Chromatisch parallel"], a: 1, fb: "Am7 ersetzt CMaj7 durch diatonische I→VI-Substitution. CMaj7 (I) und Am7 (VIm) teilen C, E, G — drei gemeinsame Töne. Es ist eine sanfte Trugkadenz: die Kadenz V7→I wird zu V7→VIm — weniger endgültig, aber sehr ausdrucksstark." },
];

const questionsIt: Question[] = [{ q: "Cos'è la riarmonizzazione?", opts: ["Suonare più note", "Sostituire gli accordi di una progressione esistente con altri mantenendo la melodia", "Cambiare la melodia di un brano", "Trasporre in un'altra tonalità"], a: 1, fb: "La riarmonizzazione conserva la melodia ma sostituisce gli accordi. Condizione fondamentale: ogni nota melodica deve essere compatibile con il nuovo accordo (fondamentale, terza, quinta, settima o estensione). È scultura armonica." },
{ q: "Qual è la condizione fondamentale di una riarmonizzazione riuscita?", opts: ["Usare accordi più complessi", "La nota melodica deve essere compatibile con il nuovo accordo", "Restare sempre nella stessa tonalità", "Usare solo la sostituzione di tritono"], a: 1, fb: "Ogni nota melodica deve appartenere al nuovo accordo o essere una tensione accettabile: fondamentale, terza, quinta, settima o estensione (9a, 11a, 13a). Se la melodia suona stonata sul nuovo accordo, la riarmonizzazione fallisce." },
{ q: "Una nota melodica è compatibile con un accordo se è:", opts: ["Solo la fondamentale", "Fondamentale, terza, quinta, settima o estensione (9a/11a/13a)", "Solo la terza o la quinta", "Qualsiasi nota"], a: 1, fb: "Le note compatibili: fondamentale (1), terza (3), quinta (5), settima (7) e le estensioni (9a, 11a, 13a). Se la melodia canta Mi su un accordo riarmonizzato, quell'accordo deve contenere Mi in una di queste posizioni." },
{ q: "Riarmonizzare una progressione equivale a:", opts: ["Cambiare il tempo", "Sostituire tutto o parte degli accordi conservando la melodia intatta", "Aggiungere nuovi strumenti", "Cambiare la tonalità"], a: 1, fb: "Riarmonizzare = cambiare gli accordi, mantenere la melodia. La melodia è l'elemento fisso; gli accordi sottostanti sono modificabili finché ogni nota melodica rimane compatibile. È l'arte di trovare nuovi 'vestiti armonici' per una stessa melodia." },
{ q: "Quale coppia di accordi può sostituirsi nella sostituzione diatonica?", opts: ["I e II", "I e VI", "V e IV", "III e VII"], a: 1, fb: "I e VI condividono due o tre note comuni (in C: CMaj7 condivide Mi e Sol con Am7 — e anche Do). Questa vicinanza permette di permutarli senza influenzare la melodia. Anche II e IV si sostituiscono (Dm7 e FMaj7 condividono Fa e La)." },
{ q: "In C maggiore, quali accordi si sostituiscono nella sostituzione diatonica?", opts: ["CMaj7 ↔ Dm7", "CMaj7 ↔ Am7  ·  Dm7 ↔ FMaj7", "G7 ↔ Em7", "Dm7 ↔ G7"], a: 1, fb: "CMaj7 e Am7 condividono Mi e Sol (e Do). FMaj7 e Dm7 condividono Fa e La. Queste note comuni creano una continuità armonica sufficiente perché la melodia rimanga logica sull'accordo sostituito." },
{ q: "Perché I e VI possono sostituirsi?", opts: ["Perché hanno la stessa fondamentale", "Perché condividono due o tre note comuni", "Perché sono a distanza di tritono", "Perché hanno la stessa qualità maggiore/minore"], a: 1, fb: "In C: CMaj7 = C E G B, Am7 = A C E G. Note comuni: Do, Mi, Sol. La melodia suona bene su Am7 se cantava Do, Mi o Sol su CMaj7. Più note comuni = sostituzione più naturale." },
{ q: "La sostituzione diatonica 'II ↔ IV' in C maggiore corrisponde a:", opts: ["Dm7 ↔ G7", "Dm7 ↔ FMaj7", "Am7 ↔ Em7", "CMaj7 ↔ FMaj7"], a: 1, fb: "IIm7 = Dm7 (D F A C), IV = FMaj7 (F A C E). Note comuni: Fa, La, Do. Questi due accordi hanno una funzione di sottodominante simile e possono sostituirsi in molti contesti." },
{ q: "Sostituire CMaj7 con Am7 (I → VI) crea quale effetto?", opts: ["Una risoluzione più forte", "Un leggero colore minore, più morbido — 'risoluzione ingannevole dolce'", "Una tensione massima", "Un cambiamento di tonalità"], a: 1, fb: "Am7 condivide le note di CMaj7 ma il suo fondamento minore crea un colore più morbido, talvolta malinconico. È una 'cadenza ingannevole dolce' — la risoluzione attesa su I arriva ma sfumata dal VIm, meno definitiva." },
{ q: "Il sostituto di tritono di G7 è:", opts: ["F#7", "Db7", "Ab7", "C#7"], a: 1, fb: "Db7 si trova a un tritono (6 semitoni) sopra G7. Db7 (Db F Ab Cb) condivide lo stesso tritono di G7 (Si/Cb e Fa) — le note di tensione sono identiche ma i loro ruoli si invertono. Il basso scende di un semitono Db→C." },
{ q: "Cosa condividono G7 e Db7, rendendo possibile la sostituzione di tritono?", opts: ["La fondamentale", "La stessa quinta", "Lo stesso tritono — Si e Fa (note di tensione)", "La stessa settima"], a: 2, fb: "G7 contiene Si–Fa (tritono). Db7 contiene Fa–Cb (= Si, enarmonico). Queste due note di tensione sono identiche in entrambi gli accordi ma i loro nomi si invertono. È questa condivisione che rende la sostituzione coerente armonicamente." },
{ q: "Quale effetto crea la sostituzione di tritono sul basso?", opts: ["Un salto di quinta", "Un movimento cromatico discendente (semitono) verso I", "Un movimento ascendente per semitoni", "Un basso fisso"], a: 1, fb: "Db7 → CMaj7: il basso scende di un semitono. Rispetto a G7 → CMaj7 (quinta discendente), è molto più elegante. Questo movimento cromatico è caratteristico del jazz bebop e della riarmonizzazione jazz." },
{ q: "Il sostituto di tritono di D7 (dominante di GMaj7) è:", opts: ["Eb7", "Ab7", "Bb7", "F#7"], a: 1, fb: "Un tritono sopra D (Re) = Ab (La bemolle). Ab7 è il sostituto di tritono di D7. In II–V–I di G: Am7–D7–GMaj7 può diventare Am7–Ab7–GMaj7 (basso La–Lab–Sol, discesa cromatica)." },
{ q: "Perché la sostituzione di tritono funziona armonicamente?", opts: ["Perché i due accordi hanno la stessa quinta", "Perché V7 e ♭II7 condividono le stesse note di tensione (il tritono), solo con i ruoli invertiti", "Perché sono nella stessa scala", "Perché la fondamentale rimane la stessa"], a: 1, fb: "Il tritono di V7 (es. Si–Fa di G7) è anche il tritono di ♭II7 (Fa–Si di Db7). I due accordi creano la stessa tensione di risoluzione verso I — stesso 'carburante', fondamentale diversa. Il basso scende di un semitono invece di una quinta." },
{ q: "In 'Dm7 – Db7 – CMaj7', Db7 sostituisce quale accordo originale?", opts: ["Dm7 (II)", "G7 (V) per sostituzione di tritono", "Am7 (VI)", "Em7 (III)"], a: 1, fb: "Db7 è il sostituto di tritono di G7. La progressione originale Dm7–G7–CMaj7 diventa Dm7–Db7–CMaj7. Il basso D–Db–C scende cromaticamente, rendendo la progressione molto elegante." },
{ q: "Cos'è un prestito modale nella riarmonizzazione?", opts: ["Usare un accordo di un altro strumento", "Sostituire un accordo con il suo omonimo della scala minore parallela", "Usare il modo dorico", "Prendere in prestito accordi dal jazz modale"], a: 1, fb: "Il prestito modale prende un accordo dalla tonalità omonima minore. In C maggiore, si prende in prestito da C minore: Fm (IVm), Cm (Im), AbMaj7 (bVI), Bb7 (bVII). Questi accordi apportano un colore scuro e modale in un contesto maggiore." },
{ q: "In C maggiore, 'FMaj7 → Fm' è un prestito da:", opts: ["La scala di Fa maggiore", "C minore parallelo (IVm = Fm nella scala omonima minore)", "La scala di Re dorico", "La scala pentatonica"], a: 1, fb: "Fm (F Ab C Eb) è il IV grado di C minore. Lo si prende in prestito dalla tonalità omonima minore. Lab (3a di Fm) crea il colore scuro. Bill Evans usava frequentemente questa 'bemollizzazione' del IV nei suoi standard." },
{ q: "Quale nota caratteristica appare quando si sostituisce FMaj7 con Fm in C maggiore?", opts: ["Fa#", "Lab (bIII di C minore)", "Do#", "Sib"], a: 1, fb: "Fm = F Ab C Eb. Il Lab (Ab) è la nota estranea proveniente da C minore. Questa bemollizzazione della terza (La→Lab) caratterizza il prestito modale — colore scuro immediatamente riconoscibile." },
{ q: "Quali accordi si possono prendere in prestito da C minore parallelo?", opts: ["Solo Cm", "Fm (IVm), Cm (Im), AbMaj7 (bVI), Bb7 (bVII), EbMaj7 (bIII)", "Solo Fm e Cm", "Solo G7 e D7"], a: 1, fb: "La scala di C minore fornisce: Im=Cm, IIm7b5=Dm7b5, bIII=EbMaj7, IVm=Fm, V7=G7, bVI=AbMaj7, bVII=Bb7. Tutti possono essere presi in prestito in C maggiore. I più comuni: Fm, AbMaj7, Bb7 (per i loro bemolli espressivi)." },
{ q: "Perché il prestito modale crea un effetto commovente?", opts: ["Perché è più facile da suonare", "Perché introduce bemolli inattesi che oscurano momentaneamente un colore maggiore", "Perché elimina il tritono", "Perché è imposto dalla forma AABA"], a: 1, fb: "I prestiti modali (IV→IVm, I→Im) introducono bemolli provenienti dal minore parallelo — Lab, Mib, Sib. Questi colori scuri inattesi in un contesto maggiore creano un contrasto espressivo potente — firma del suono di Bill Evans." },
{ q: "Cos'è l'armonizzazione parallela?", opts: ["Suonare due melodie simultaneamente", "Spostare lo stesso tipo di accordo cromaticamente sotto la melodia", "Armonizzare alla terza", "Raddoppiare le voci all'ottava"], a: 1, fb: "L'armonizzazione parallela sposta un tipo di accordo identico (es. Maj7) cromaticamente o per toni seguendo la melodia. CMaj7–DbMaj7–DMaj7: stessa struttura, basi successive. Tecnica impressionista adottata dal jazz." },
{ q: "CMaj7 → DbMaj7 → DMaj7 è un esempio di:", opts: ["Sostituzione di tritono successiva", "Armonizzazione parallela cromatica ascendente", "Sostituzione diatonica", "Ciclo delle quinte"], a: 1, fb: "Stesso tipo di accordo (Maj7) spostato cromaticamente (C→Db→D). Il condotto delle voci è meccanico — tutte le voci si muovono dello stesso intervallo. La melodia che fluttua sopra crea l'interesse armonico." },
{ q: "Quale compositore è maggiormente associato all'armonizzazione parallela?", opts: ["Bach", "Beethoven", "Debussy", "Vivaldi"], a: 2, fb: "Debussy ha sistematizzato gli accordi paralleli nei suoi preludi e notturni. L'impressionismo francese ha introdotto questa tecnica che il jazz ha adottato — in particolare Bill Evans su My Foolish Heart e Peace Piece." },
{ q: "Nell'armonizzazione parallela, cosa crea l'interesse armonico?", opts: ["La complessità degli accordi", "La melodia — gli accordi si spostano in blocco sotto di essa", "Il movimento rapido del basso", "Le note di tensione"], a: 1, fb: "Gli accordi paralleli sono 'neutri' di per sé. È la melodia immutabile a creare la logica e l'interesse. La successione cromatica degli accordi crea l'effetto impressionista; la melodia guida l'ascoltatore." },
{ q: "Se la melodia canta 'Mi' su un accordo riarmonizzato, quale accordo è adatto?", opts: ["Fm7 (Mi assente)", "CMaj7 (Mi = 3a)", "Dm7b5 (Mi assente)", "Bb7 (Mi assente)"], a: 1, fb: "CMaj7 = C E G B. Mi (E) è la 3a di CMaj7 — nota costitutiva. La melodia Mi è perfettamente compatibile. Regola: la nota melodica deve essere 1, 3, 5, 7 o estensione dell'accordo." },
{ q: "Se la melodia canta 'La' su un accordo riarmonizzato, quale funziona?", opts: ["Dm7 (La = 5a)", "FMaj7 (La = 3a)", "Am7 (La = fondamentale)", "Tutti funzionano"], a: 3, fb: "La (A) è: 5a di Dm7, 3a di FMaj7, fondamentale di Am7. I tre accordi sono compatibili con la melodia La. Ecco perché la riarmonizzazione offre così tante possibilità — una stessa nota può appartenere a molti accordi." },
{ q: "Per verificare la compatibilità melodia/accordo, la nota deve essere:", opts: ["Più alta del basso", "1, 3, 5, 7 o estensione (9a, 11a, 13a) dell'accordo", "Nella stessa ottava della fondamentale", "Inferiore alla 5a"], a: 1, fb: "Regola universale: fondamentale (1), terza (3), quinta (5), settima (7) o estensione (9a, 11a, 13a). Le note al di fuori di queste categorie creano attriti involontari. Una b9 non intenzionale suona stonata." },
{ q: "Perché 'Si' (B naturale) è problematico su un accordo Fm?", opts: ["Perché Si è troppo grave", "Perché Si (= 4a aumentata / tritono di Fm) non è un'estensione naturale di un accordo minore", "Perché Si è sempre dissonante", "Perché Si è troppo acuto"], a: 1, fb: "Fm = F Ab C Eb. Si (B) è la 4a aumentata di Fm — un tritono rispetto alla fondamentale Fa. Non è un'estensione naturale. Se la melodia canta Si sopra Fm, la riarmonizzazione suona stonata: bisogna scegliere un altro accordo." },
{ q: "In 'Dm7 – Db7 – CMaj7' con melodia Sol–Sol–Sol, Db7 è compatibile?", opts: ["No — Sol è la 4a bemollizzata di Db7, molto dissonante", "Sì — Sol è la quinta di Db7", "No — Sol non è mai compatibile", "Sì — Sol è sempre possibile"], a: 0, fb: "Db7 = Db F Ab Cb. Sol (G) rispetto a Db: è la quarta aumentata (= tritono). Molto dissonante, non naturale. Prima di validare una riarmonizzazione, verificare ogni nota melodica su ogni nuovo accordo." },
{ q: "Bill Evans è associato a quale corrente del jazz?", opts: ["Bebop degli anni '40", "Jazz cool e post-bop degli anni '50–'70", "Free jazz", "Dixieland"], a: 1, fb: "Bill Evans (1929–1980) è una figura centrale del jazz cool e post-bop. Il suo lavoro con il Miles Davis Sextet (Kind of Blue, 1959) e il suo trio hanno definito un suono introspettivo armonicamente sofisticato." },
{ q: "Bill Evans è famoso per le sue riarmonizzazioni in cui:", opts: ["Elimina tutti gli accordi di passaggio", "Aggiunge prestiti modali, estensioni e sostituzioni sottili trasformando progressioni semplici in opere sofisticate", "Suona solo in minore", "Evita le dissonanze"], a: 1, fb: "Evans trasformava standard semplici (Autumn Leaves, Waltz for Debby) con prestiti modali (IVm, bVI), estensioni (9a, b11), sostituzioni di tritono delicate e un condotto delle voci impeccabile." },
{ q: "Su 'My Foolish Heart', Evans utilizza in particolare:", opts: ["Il modo locrio esclusivamente", "Accordi paralleli cromatici e prestiti dal minore parallelo", "Il jazz blues di 12 misure", "Solo triadi"], a: 1, fb: "Evans riarmonizza My Foolish Heart con accordi paralleli cromatici (impressione debussiana) e prestiti modali (IVm, bVI) che scuriscono il colore. Riarmonizzazione 'a blocchi' caratteristica del suo stile." },
{ q: "Qual è il contributo principale di Bill Evans alla riarmonizzazione jazz?", opts: ["Inventare la sostituzione di tritono", "Dimostrare che gli standard possono essere trasformati armonicamente con sostituzioni sottili senza mai disturbare la melodia", "Creare la forma blues", "Introdurre il modo dorico"], a: 1, fb: "Evans ha dimostrato che una riarmonizzazione può essere sottile e preservare il 'carattere' di uno standard. La sua versione di Waltz for Debby illustra come riarmonizzare per amplificare — e non mascherare — la bellezza originale." },
{ q: "Keith Jarrett e Brad Mehldau hanno continuato la tradizione di:", opts: ["Charlie Parker (bebop puro)", "Bill Evans — riarmonizzazione introspettiva, prestiti modali e condotto delle voci curato", "Miles Davis (elettrico)", "Oscar Peterson (stride)"], a: 1, fb: "Jarrett e Mehldau ereditano direttamente da Evans: stessa attenzione al condotto delle voci, stesso uso dei prestiti modali, stessa capacità di riarmonizzare uno standard preservandone l'identità emotiva." },
{ q: "Brad Mehldau è noto per riarmonizzare canzoni di:", opts: ["Beethoven", "Radiohead, Nick Drake e altri artisti pop/rock", "Vivaldi", "Wagner"], a: 1, fb: "Brad Mehldau riarmonizza canzoni pop (Radiohead: Knives Out, Exit Music for a Film; Nick Drake) con il linguaggio jazz (estensioni, sostituzioni, prestiti modali). Riarmonizzazione cross-genre — melodia pop, armonia jazz." },
{ q: "Perché il condotto delle voci è cruciale nella riarmonizzazione?", opts: ["Perché determina il tempo", "Perché cambiamenti di accordi bruschi creano salti poco eleganti — la fluidità delle voci interne è un criterio di qualità", "Perché elimina le dissonanze", "Perché è imposto da Fux"], a: 1, fb: "Una riarmonizzazione può essere tecnicamente corretta (note compatibili) ma suonare bruscamente se le voci interne fanno grandi salti. Una buona riarmonizzazione sposta le voci per semitoni o toni — minimo movimento, massima fluidità." },
{ q: "Quale regola di condotto delle voci si applica nella riarmonizzazione?", opts: ["Le voci devono sempre salire", "Preferire il movimento congiunto (semitono, tono) per le voci interne", "Non raddoppiare mai la fondamentale", "Mettere sempre la melodia alla voce più grave"], a: 1, fb: "Nella riarmonizzazione: movimento delle voci per piccoli intervalli (congiunto). G7 → Db7: le voci interne Si–Re–Fa trovano facilmente Fa–Lab–Si in Db7 per movimento di semitoni. È ciò che Evans padroneggiava perfettamente." },
{ q: "Come la sostituzione di tritono facilita il condotto delle voci?", opts: ["Perché elimina una voce", "Perché le note di tensione (tritono) condivise tra V7 e ♭II7 permettono un condotto molto fluido", "Perché ha solo 2 note", "Perché è sempre in posizione chiusa"], a: 1, fb: "G7 (G B D F) e Db7 (Db F Ab Cb) condividono Si/Cb e Fa. La sostituzione di tritono crea un accordo vicino con note comuni — le voci non devono quasi muoversi. Ecco perché questa sostituzione sembra 'morbida' nonostante il cambiamento radicale di fondamentale." },
{ q: "Cos'è riarmonizzare 'a blocchi'?", opts: ["Cambiare tutti gli accordi in una volta sola", "Modificare un accordo alla volta, lasciando il resto intatto", "Raggruppare gli accordi a 4", "Suonare tutti gli accordi simultaneamente"], a: 1, fb: "Riarmonizzare a blocchi = modificare un accordo alla volta nella progressione. Es. cambiare solo V7 per sostituzione di tritono, lasciando gli altri accordi originali. È l'approccio più sicuro — si controlla l'impatto di ogni cambiamento." },
{ q: "La 'riarmonizzazione completa' consiste nel:", opts: ["Suonare più forte", "Sostituire interamente la griglia originale con una nuova progressione mantenendo la melodia", "Trasporre in un'altra tonalità", "Suonare senza accordi"], a: 1, fb: "La riarmonizzazione completa ricostruisce totalmente la griglia. La melodia resta; gli accordi sottostanti sono interamente nuovi. Esempio: Coltrane prende My Favorite Things (melodia intatta) e crea una griglia modale totalmente diversa." },
{ q: "Perché si riarmonizza uno standard jazz?", opts: ["Perché gli accordi originali sono errati", "Per rinnovare l'espressione artistica, esplorare nuovi colori armonici e personalizzare l'interpretazione", "Perché è imposto dalle regole del jazz", "Per facilitare l'improvvisazione"], a: 1, fb: "La riarmonizzazione è uno strumento espressivo. Permette a un musicista di 'firmare' la propria versione di uno standard, esplorare nuove emozioni armoniche, sorprendere l'ascoltatore familiare con la versione originale. È composizione in tempo reale." },
{ q: "Su quale repertorio viene più spesso applicata la riarmonizzazione?", opts: ["La musica barocca", "Gli standard jazz e le melodie popolari conosciute", "Le sinfonie classiche", "Solo la musica contemporanea"], a: 1, fb: "Si riarmonizzano soprattutto gli standard jazz (Autumn Leaves, All The Things You Are) e le melodie popolari. La melodia conosciuta dall'ascoltatore crea un contrasto con gli accordi inattesi — l'effetto sorpresa è al cuore della riarmonizzazione." },
{ q: "La sostituzione 'Dm7 – Db7 – Am7' combina:", opts: ["Due sostituzioni di tritono", "Sostituzione di tritono su G7 + sostituzione diatonica I→VI su CMaj7", "Due prestiti modali", "Armonizzazione parallela + prestito modale"], a: 1, fb: "G7→Db7 (tritono) e CMaj7→Am7 (diatonica I→VI) combinate danno Dm7–Db7–Am7. Combinare le tecniche moltiplica le possibilità di riarmonizzazione. È così che Bill Evans costruiva riarmonizzazioni complesse e sottili." },
{ q: "Coltrane ha riarmonizzato 'My Favorite Things':", opts: ["Trasponendola in tutte le tonalità", "Mantenendo la melodia intatta e creando una griglia modale (dorico) interamente nuova", "Aggiungendo accordi diminuiti", "Eliminando tutte le cadenze"], a: 1, fb: "My Favorite Things di Coltrane (1960): melodia di Rodgers & Hammerstein intatta, griglia interamente modale (re dorico / mi dorico alternati). Il valzer in 3/4 resta; gli accordi sono reinventati. Riarmonizzazione completa emblematica." },
{ q: "Autumn Leaves può essere riarmonizzata:", opts: ["Cambiando solo la tonalità", "Sostituendo i V7 con i loro sostituti di tritono e sostituendo IV con IVm mantenendo la melodia", "Solo il tempo", "Solo la chiave"], a: 1, fb: "Autumn Leaves alterna II–V–I maggiore e minore. Si possono sostituire i V7 con i loro sostituti di tritono (basso cromatico), sostituire FMaj7 con Fm (prestito modale). La melodia così conosciuta contrasta con la ricchezza armonica aggiunta." },
{ q: "La tecnica dell'armonizzazione parallela è stata importata da:", opts: ["Il contrappunto barocco", "Il romanticismo tedesco", "L'impressionismo francese (Debussy, Ravel)", "Il bebop americano"], a: 2, fb: "Debussy ha introdotto gli accordi paralleli nella musica classica (inizio anni 1900) — quinte, quarte, accordi di 7a paralleli. I jazzisti americani li adottano in seguito. Evans, Jarrett e Mehldau ne sono gli eredi jazz." },
{ q: "Quale delle 4 tecniche crea il movimento di basso più cromatico?", opts: ["Sostituzione diatonica", "Sostituzione di tritono (♭II7→I = un semitono)", "Prestito modale", "Armonizzazione parallela"], a: 1, fb: "La sostituzione di tritono crea una risoluzione per semitono discendente — il movimento di basso più breve possibile. Es. Db7→CMaj7: basso Reb→Do, un semitono. Questo movimento cromatico è la caratteristica acustica più riconoscibile di questa tecnica." },
{ q: "Quale tecnica introduce bemolli inattesi in un contesto maggiore?", opts: ["Sostituzione di tritono", "Prestito modale (accordi della scala minore parallela)", "Armonizzazione parallela", "Sostituzione diatonica"], a: 1, fb: "Il prestito modale prende accordi dalla scala minore parallela — che contiene bemolli (bIII, bVI, bVII). Questi bemolli inattesi in un contesto maggiore creano il colore scuro caratteristico. Es. in C maggiore: Fm introduce Lab, AbMaj7 introduce Lab e Mib." },
{ q: "Quale tecnica conserva esattamente le stesse note di tensione dell'accordo originale?", opts: ["Prestito modale", "Armonizzazione parallela", "Sostituzione di tritono — il tritono è condiviso", "Sostituzione diatonica"], a: 2, fb: "La sostituzione di tritono condivide lo stesso tritono tra V7 e ♭II7. G7 e Db7 hanno entrambi Si e Fa (= Cb) — stesse note di tensione, ruoli invertiti. Ecco perché la risoluzione sembra 'diversa ma familiare'." },
{ q: "Una riarmonizzazione di qualità si riconosce:", opts: ["Dal numero di accordi usati", "Dalla fluidità del condotto delle voci, la compatibilità di ogni nota melodica e la coerenza espressiva", "Dal tempo di esecuzione", "Dall'assenza di dissonanze"], a: 1, fb: "Criteri: (1) ogni nota melodica è compatibile con il nuovo accordo, (2) le voci interne si muovono per piccoli intervalli, (3) l'effetto espressivo amplifica (non maschera) la melodia. È tecnica E arte." },
{ q: "Quale rischio principale esiste nella riarmonizzazione?", opts: ["Usare troppo pochi accordi", "Sacrificare la fluidità melodica — se troppo radicale, la melodia sembra 'persa' sugli accordi", "Suonare troppo piano", "Suonare gli accordi troppo velocemente"], a: 1, fb: "Il pericolo principale: incompatibilità melodia/accordo. Se una nota melodica non si trova nell'accordo sostituito, la sonorità è aggressiva e la melodia galleggia nel vuoto. La fluidità melodica ha sempre la precedenza sulla sofisticazione armonica." },
{ q: "Cos'è il 'bVI prestito' in C maggiore?", opts: ["Bm7b5", "AbMaj7 (preso in prestito da C minore — bVI)", "Am7 (VI diatonico)", "Fm7"], a: 1, fb: "bVI in C maggiore = AbMaj7. Questo accordo è preso in prestito da C minore parallelo (dove il 6° grado è bemolle). AbMaj7 introduce Lab, Mib e Do — colore molto scuro e romantico. Molto usato nel jazz post-bop e nel pop (Let It Be include questo colore)." },
  { q: "Nella sostituzione diatonica, quante note comuni idealmente?", opts: ["Nessuna — gli accordi devono contrastare", "Almeno 2 note comuni (idealmente 3)", "Esattamente 1 nota comune", "Tutte le note comuni"], a: 1, fb: "Almeno 2 note comuni garantisce che la melodia rimanga logica sull'accordo sostituito. CMaj7–Am7 condividono 3 note — sostituzione molto naturale. Meno note comuni = sostituzione più 'rischiosa' melodicamente." },
  { q: "Riarmonizzare 'Dm7–G7–CMaj7' in 'Dm7–G7–Am7' è una sostituzione:", opts: ["Tritono su G7", "Diatonica I→VI su CMaj7", "Modale (Am7 preso dal minore)", "Cromatica parallela"], a: 1, fb: "Am7 sostituisce CMaj7 con sostituzione diatonica I→VI. CMaj7 (I) e Am7 (VIm) condividono Do, Mi, Sol — tre note comuni. È una cadenza evitata dolce: la cadenza V7→I diventa V7→VIm — meno definitiva ma molto espressiva." },
];

const questionsPt: Question[] = [{ q: "O que é a reharmonização?", opts: ["Tocar mais notas", "Substituir os acordes de uma progressão existente por outros, conservando a melodia", "Mudar a melodia de uma peça", "Transpor para outra tonalidade"], a: 1, fb: "A reharmonização conserva a melodia, mas substitui os acordes. Condição fundamental: cada nota melódica deve ser compatível com o novo acorde (fundamental, terça, quinta, sétima ou extensão). É uma escultura harmônica." },
{ q: "Qual é a condição fundamental de uma reharmonização bem-sucedida?", opts: ["Usar acordes mais complexos", "A nota melódica deve ser compatível com o novo acorde", "Permanecer sempre na mesma tonalidade", "Usar apenas a substituição de trítono"], a: 1, fb: "Cada nota melódica deve pertencer ao novo acorde ou ser uma tensão aceitável: fundamental, terça, quinta, sétima ou extensão (9ª, 11ª, 13ª). Se a melodia soa errada sobre o novo acorde, a reharmonização falha." },
{ q: "Uma nota melódica é compatível com um acorde se ela for:", opts: ["Apenas a fundamental", "Fundamental, terça, quinta, sétima ou extensão (9ª/11ª/13ª)", "Apenas a terça ou a quinta", "Qualquer nota"], a: 1, fb: "As notas compatíveis: fundamental (1), terça (3), quinta (5), sétima (7) e as extensões (9ª, 11ª, 13ª). Se a melodia canta Mi sobre um acorde reharmonizado, esse acorde deve conter Mi em uma dessas posições." },
{ q: "Reharmonizar uma progressão equivale a:", opts: ["Mudar o andamento", "Substituir todos ou parte dos acordes conservando a melodia intacta", "Adicionar novos instrumentos", "Mudar a tonalidade"], a: 1, fb: "Reharmonizar = mudar os acordes, manter a melodia. A melodia é o elemento fixo; os acordes abaixo são modificáveis desde que cada nota melódica permaneça compatível. É a arte de encontrar novas 'roupagens harmônicas' para um mesmo tema." },
{ q: "Qual par de acordes pode se substituir na substituição diatônica?", opts: ["I e II", "I e VI", "V e IV", "III e VII"], a: 1, fb: "I e VI compartilham duas a três notas comuns (em C: CMaj7 compartilha Mi e Sol com Am7 — e também Do). Essa proximidade permite permutá-los sem afetar a melodia. II e IV também se substituem (Dm7 e FMaj7 compartilham Fa e La)." },
{ q: "Em C maior, quais acordes se substituem na substituição diatônica?", opts: ["CMaj7 ↔ Dm7", "CMaj7 ↔ Am7  ·  Dm7 ↔ FMaj7", "G7 ↔ Em7", "Dm7 ↔ G7"], a: 1, fb: "CMaj7 e Am7 compartilham Mi e Sol (e Do). FMaj7 e Dm7 compartilham Fa e La. Essas notas comuns criam uma continuidade harmônica suficiente para que a melodia permaneça lógica sobre o acorde substituído." },
{ q: "Por que I e VI podem se substituir?", opts: ["Porque têm a mesma fundamental", "Porque compartilham duas a três notas comuns", "Porque estão a distância de trítono", "Porque têm a mesma qualidade maior/menor"], a: 1, fb: "Em C: CMaj7 = C E G B, Am7 = A C E G. Notas comuns: Do, Mi, Sol. A melodia soa correta sobre Am7 se cantava Do, Mi ou Sol sobre CMaj7. Mais notas comuns = substituição mais natural." },
{ q: "A substituição diatônica 'II ↔ IV' em C maior corresponde a:", opts: ["Dm7 ↔ G7", "Dm7 ↔ FMaj7", "Am7 ↔ Em7", "CMaj7 ↔ FMaj7"], a: 1, fb: "IIm7 = Dm7 (D F A C), IV = FMaj7 (F A C E). Notas comuns: Fa, La, Do. Esses dois acordes têm função subdominante similar e podem se substituir em muitos contextos." },
{ q: "Substituir CMaj7 por Am7 (I → VI) cria qual efeito?", opts: ["Uma resolução mais forte", "Uma leve cor menor, mais suave — 'resolução enganosa suave'", "Tensão máxima", "Uma mudança de tonalidade"], a: 1, fb: "Am7 compartilha as notas de CMaj7, mas sua base menor cria uma cor mais suave, às vezes melancólica. É uma 'cadência enganosa suave' — a resolução esperada em I chega, mas tingida de VIm, menos definitiva." },
{ q: "O substituto de trítono de G7 é:", opts: ["F#7", "Db7", "Ab7", "C#7"], a: 1, fb: "Db7 está localizado um trítono (6 semitons) acima de G7. Db7 (Db F Ab Cb) compartilha o mesmo trítono que G7 (Si/Cb e Fa) — as notas de tensão são idênticas, mas seus papéis se invertem. O baixo desce um semitom: Db→C." },
{ q: "O que G7 e Db7 compartilham, tornando a substituição de trítono possível?", opts: ["A fundamental", "A mesma quinta", "O mesmo trítono — Si e Fa (notas de tensão)", "A mesma sétima"], a: 2, fb: "G7 contém Si–Fa (trítono). Db7 contém Fa–Cb (= Si, enarmônico). Essas duas notas de tensão são idênticas nos dois acordes, mas seus nomes se invertem. É esse compartilhamento que torna a substituição coerente harmonicamente." },
{ q: "Qual efeito a substituição de trítono cria no baixo?", opts: ["Um salto de quinta", "Um movimento cromático descendente (semitom) em direção a I", "Um movimento ascendente por semitons", "Um baixo fixo"], a: 1, fb: "Db7 → CMaj7: o baixo desce um semitom. Comparado a G7 → CMaj7 (quinta descendente), é muito mais elegante. Esse movimento cromático é característico do jazz bebop e da reharmonização jazz." },
{ q: "O substituto de trítono de D7 (dominante de GMaj7) é:", opts: ["Eb7", "Ab7", "Bb7", "F#7"], a: 1, fb: "Um trítono acima de D (Ré) = Ab (Lá bemol). Ab7 é o substituto de trítono de D7. No II–V–I de G: Am7–D7–GMaj7 pode se tornar Am7–Ab7–GMaj7 (baixo La–Lab–Sol, descida cromática)." },
{ q: "Por que a substituição de trítono funciona harmonicamente?", opts: ["Porque os dois acordes têm a mesma quinta", "Porque V7 e ♭II7 compartilham as mesmas notas de tensão (o trítono), apenas com os papéis invertidos", "Porque estão na mesma escala", "Porque a fundamental permanece a mesma"], a: 1, fb: "O trítono de V7 (ex. Si–Fa de G7) é também o trítono de ♭II7 (Fa–Si de Db7). Os dois acordes criam a mesma tensão de resolução em direção a I — mesmo 'combustível', fundamental diferente. O baixo desce por semitom em vez de quinta." },
{ q: "Em 'Dm7 – Db7 – CMaj7', Db7 substitui qual acorde original?", opts: ["Dm7 (II)", "G7 (V) por substituição de trítono", "Am7 (VI)", "Em7 (III)"], a: 1, fb: "Db7 é o substituto de trítono de G7. A progressão original Dm7–G7–CMaj7 se torna Dm7–Db7–CMaj7. O baixo D–Db–C desce cromaticamente, tornando a progressão muito elegante." },
{ q: "O que é um empréstimo modal em reharmonização?", opts: ["Usar um acorde de outro instrumento", "Substituir um acorde pelo seu homônimo da escala menor paralela", "Usar o modo dórico", "Emprestar acordes do jazz modal"], a: 1, fb: "O empréstimo modal toma um acorde da tonalidade homônima menor. Em C maior, empresta-se de C menor: Fm (IVm), Cm (Im), AbMaj7 (bVI), Bb7 (bVII). Esses acordes trazem uma cor sombria e modal em um contexto maior." },
{ q: "Em C maior, 'FMaj7 → Fm' é um empréstimo de:", opts: ["A escala de Fa maior", "C menor paralelo (IVm = Fm na escala homônima menor)", "A escala de Ré dórico", "A escala pentatônica"], a: 1, fb: "Fm (F Ab C Eb) é o IV grau de C menor. Empresta-se da tonalidade homônima menor. Lab (3ª de Fm) cria a cor sombria. Bill Evans usava frequentemente essa 'bemolização' do IV nos seus standards." },
{ q: "Qual nota característica aparece quando se substitui FMaj7 por Fm em C maior?", opts: ["Fa#", "Lab (bIII de C menor)", "Do#", "Sib"], a: 1, fb: "Fm = F Ab C Eb. O Lab (Ab) é a nota estranha proveniente de C menor. Essa bemolização da terça (La→Lab) caracteriza o empréstimo modal — cor sombria imediatamente reconhecível." },
{ q: "Quais acordes podem ser emprestados de C menor paralelo?", opts: ["Apenas Cm", "Fm (IVm), Cm (Im), AbMaj7 (bVI), Bb7 (bVII), EbMaj7 (bIII)", "Apenas Fm e Cm", "G7 e D7 somente"], a: 1, fb: "A escala de C menor fornece: Im=Cm, IIm7b5=Dm7b5, bIII=EbMaj7, IVm=Fm, V7=G7, bVI=AbMaj7, bVII=Bb7. Todos podem ser emprestados em C maior. Os mais comuns: Fm, AbMaj7, Bb7 (pelos seus bemóis expressivos)." },
{ q: "Por que o empréstimo modal cria um efeito tocante?", opts: ["Porque é mais fácil de tocar", "Porque introduz bemóis inesperados que escurecem momentaneamente uma cor maior", "Porque elimina o trítono", "Porque é imposto pela forma AABA"], a: 1, fb: "Os empréstimos modais (IV→IVm, I→Im) introduzem bemóis provenientes do menor paralelo — Lab, Mib, Sib. Essas cores sombrias inesperadas em um contexto maior criam um contraste expressivo poderoso — assinatura do som de Bill Evans." },
{ q: "O que é a harmonização paralela?", opts: ["Tocar duas melodias simultaneamente", "Deslocar o mesmo tipo de acorde cromaticamente sob a melodia", "Harmonizar em terças", "Dobrar as vozes à oitava"], a: 1, fb: "A harmonização paralela desloca um tipo idêntico de acorde (ex. Maj7) cromaticamente ou por tons, seguindo a melodia. CMaj7–DbMaj7–DMaj7: mesma estrutura, bases sucessivas. Técnica impressionista adotada pelo jazz." },
{ q: "CMaj7 → DbMaj7 → DMaj7 é um exemplo de:", opts: ["Substituição de trítono sucessiva", "Harmonização paralela cromática ascendente", "Substituição diatônica", "Ciclo das quintas"], a: 1, fb: "Mesmo tipo de acorde (Maj7) deslocado cromaticamente (C→Db→D). A condução de vozes é mecânica — todas as vozes se movem pelo mesmo intervalo. A melodia flutuando acima cria o interesse harmônico." },
{ q: "Qual compositor é mais associado à harmonização paralela?", opts: ["Bach", "Beethoven", "Debussy", "Vivaldi"], a: 2, fb: "Debussy sistematizou os acordes paralelos em seus prelúdios e noturnos. O impressionismo francês introduziu essa técnica que o jazz adotou — notadamente Bill Evans em My Foolish Heart e Peace Piece." },
{ q: "Na harmonização paralela, o que cria o interesse harmônico?", opts: ["A complexidade dos acordes", "A melodia — os acordes se deslocam em bloco sob ela", "O movimento rápido do baixo", "As notas de tensão"], a: 1, fb: "Os acordes paralelos são 'neutros' em si mesmos. É a melodia imutável que cria a lógica e o interesse. A sucessão cromática dos acordes cria o efeito impressionista; a melodia conduz o ouvinte." },
{ q: "Se a melodia canta 'Mi' sobre um acorde reharmonizado, qual acorde é adequado?", opts: ["Fm7 (Mi ausente)", "CMaj7 (Mi = 3ª)", "Dm7b5 (Mi ausente)", "Bb7 (Mi ausente)"], a: 1, fb: "CMaj7 = C E G B. Mi (E) é a 3ª de CMaj7 — nota constitutiva. A melodia Mi é perfeitamente compatível. Regra: a nota melódica deve ser 1, 3, 5, 7 ou extensão do acorde." },
{ q: "Se a melodia canta 'La' sobre um acorde reharmonizado, qual funciona?", opts: ["Dm7 (La = 5ª)", "FMaj7 (La = 3ª)", "Am7 (La = fundamental)", "Todos funcionam"], a: 3, fb: "La (A) é: 5ª de Dm7, 3ª de FMaj7, fundamental de Am7. Os três acordes são compatíveis com a melodia La. É por isso que a reharmonização oferece tantas possibilidades — uma mesma nota pode pertencer a muitos acordes." },
{ q: "Para verificar a compatibilidade melodia/acorde, a nota deve ser:", opts: ["Mais alta do que o baixo", "1, 3, 5, 7 ou extensão (9ª, 11ª, 13ª) do acorde", "Na mesma oitava que a fundamental", "Inferior à 5ª"], a: 1, fb: "Regra universal: fundamental (1), terça (3), quinta (5), sétima (7) ou extensão (9ª, 11ª, 13ª). Notas fora dessas categorias criam atrito involuntário. Uma b9 não intencional soa errado." },
{ q: "Por que 'Si' (B natural) é problemático sobre um acorde Fm?", opts: ["Porque Si é muito grave", "Porque Si (= 4ª aumentada / trítono de Fm) não é uma extensão natural de um acorde menor", "Porque Si é sempre dissonante", "Porque Si é muito agudo"], a: 1, fb: "Fm = F Ab C Eb. Si (B) é a 4ª aumentada de Fm — um trítono em relação à fundamental Fa. Não é uma extensão natural. Se a melodia canta Si sobre Fm, a reharmonização soa errado: é preciso escolher outro acorde." },
{ q: "Em 'Dm7 – Db7 – CMaj7' com melodia Sol–Sol–Sol, Db7 é compatível?", opts: ["Não — Sol é a 4ª bemolizada de Db7, muito dissonante", "Sim — Sol é a quinta de Db7", "Não — Sol nunca é compatível", "Sim — Sol é sempre possível"], a: 0, fb: "Db7 = Db F Ab Cb. Sol (G) em relação a Db: é a quarta aumentada (= trítono). Muito dissonante, não natural. Antes de validar uma reharmonização, verifique cada nota melódica sobre cada novo acorde." },
{ q: "Bill Evans é associado a qual corrente do jazz?", opts: ["Bebop dos anos 1940", "Jazz cool e post-bop dos anos 1950–70", "Free jazz", "Dixieland"], a: 1, fb: "Bill Evans (1929–1980) é uma figura central do jazz cool e post-bop. Sua atuação com o Miles Davis Sextet (Kind of Blue, 1959) e seu trio definiram um som introspectivo e harmonicamente sofisticado." },
{ q: "Bill Evans é famoso por suas reharmonizações nas quais ele:", opts: ["Elimina todos os acordes de passagem", "Adiciona empréstimos modais, extensões e substituições sutis que transformam progressões simples em obras sofisticadas", "Toca apenas em menor", "Evita dissonâncias"], a: 1, fb: "Evans transformava standards simples (Autumn Leaves, Waltz for Debby) por empréstimos modais (IVm, bVI), extensões (9ª, b11), substituições de trítono delicadas e uma condução de vozes impecável." },
{ q: "Em 'My Foolish Heart', Evans utiliza notadamente:", opts: ["O modo lócrio exclusivamente", "Acordes paralelos cromáticos e empréstimos ao menor paralelo", "O jazz blues de 12 compassos", "Apenas tríades"], a: 1, fb: "Evans reharmoniza My Foolish Heart com acordes paralelos cromáticos (impressão debussysta) e empréstimos modais (IVm, bVI) que escurecem a cor. Reharmonização 'em blocos' característica de seu estilo." },
{ q: "Qual é a principal contribuição de Bill Evans à reharmonização jazz?", opts: ["Inventar a substituição de trítono", "Mostrar que os standards podem ser transformados harmonicamente por substituições sutis sem jamais perturbar a melodia", "Criar a forma blues", "Introduzir o modo dórico"], a: 1, fb: "Evans provou que uma reharmonização pode ser sutil e preservar o 'caráter' de um standard. Sua versão de Waltz for Debby ilustra como reharmonizar para amplificar — e não mascarar — a beleza original." },
{ q: "Keith Jarrett e Brad Mehldau continuaram a tradição de:", opts: ["Charlie Parker (bebop puro)", "Bill Evans — reharmonização introspectiva, empréstimos modais e condução de vozes cuidadosa", "Miles Davis (elétrico)", "Oscar Peterson (stride)"], a: 1, fb: "Jarrett e Mehldau herdam diretamente de Evans: mesma atenção à condução de vozes, mesmo uso dos empréstimos modais, mesma capacidade de reharmonizar um standard preservando sua identidade emocional." },
{ q: "Brad Mehldau é conhecido por reharmonizar canções de:", opts: ["Beethoven", "Radiohead, Nick Drake e outros artistas pop/rock", "Vivaldi", "Wagner"], a: 1, fb: "Brad Mehldau reharmoniza canções pop (Radiohead: Knives Out, Exit Music for a Film; Nick Drake) com a linguagem jazz (extensões, substituições, empréstimos modais). Reharmonização cross-genre — melodia pop, harmonia jazz." },
{ q: "Por que a condução de vozes é crucial na reharmonização?", opts: ["Porque determina o andamento", "Porque mudanças bruscas de acordes criam saltos pouco elegantes — a fluidez das vozes internas é um critério de qualidade", "Porque elimina as dissonâncias", "Porque é imposta por Fux"], a: 1, fb: "Uma reharmonização pode ser tecnicamente correta (notas compatíveis) mas soar bruscamente se as vozes internas fizerem grandes saltos. A boa reharmonização desloca as vozes por semitons ou tons — mínimo de movimento, máximo de fluidez." },
{ q: "Qual regra de condução de vozes se aplica na reharmonização?", opts: ["As vozes devem sempre subir", "Preferir o movimento conjunto (semitom, tom) para as vozes internas", "Nunca dobrar a fundamental", "Sempre colocar a melodia na voz mais grave"], a: 1, fb: "Na reharmonização: movimento das vozes por pequenos intervalos (conjunto). G7 → Db7: as vozes internas Si–Ré–Fa encontram facilmente Fa–Lab–Si em Db7 por movimento de semitons. É o que Evans dominava perfeitamente." },
{ q: "Como a substituição de trítono facilita a condução de vozes?", opts: ["Porque elimina uma voz", "Porque as notas de tensão (trítono) compartilhadas entre V7 e ♭II7 permitem uma condução muito fluida", "Porque tem apenas 2 notas", "Porque está sempre em posição fechada"], a: 1, fb: "G7 (G B D F) e Db7 (Db F Ab Cb) compartilham Si/Cb e Fa. A substituição de trítono cria um acorde vizinho com notas comuns — as vozes mal precisam se mover. É por isso que essa substituição parece 'suave' apesar da mudança radical de fundamental." },
{ q: "O que é reharmonizar 'em blocos'?", opts: ["Mudar todos os acordes de uma só vez", "Modificar um acorde por vez, deixando o restante intacto", "Agrupar os acordes de 4 em 4", "Tocar todos os acordes simultaneamente"], a: 1, fb: "Reharmonizar em blocos = modificar um acorde por vez na progressão. Ex.: mudar apenas V7 por substituição de trítono, deixando os demais acordes originais. É a abordagem mais segura — controla-se o impacto de cada mudança." },
{ q: "A 'reharmonização completa' consiste em:", opts: ["Tocar mais forte", "Substituir inteiramente a grade original por uma nova progressão mantendo a melodia", "Transpor para outra tonalidade", "Tocar sem acordes"], a: 1, fb: "A reharmonização completa reconstrói totalmente a grade. A melodia permanece; os acordes abaixo são inteiramente novos. Exemplo: Coltrane pega My Favorite Things (melodia intacta) e cria uma grade modal totalmente diferente." },
{ q: "Por que se reharmoniza um standard jazz?", opts: ["Porque os acordes originais estão incorretos", "Para renovar a expressão artística, explorar novas cores harmônicas e personalizar a interpretação", "Porque é imposto pelas regras do jazz", "Para facilitar a improvisação"], a: 1, fb: "A reharmonização é uma ferramenta de expressão. Ela permite ao músico 'assinar' sua versão de um standard, explorar novas emoções harmônicas e surpreender o ouvinte familiarizado com a versão original. É composição em tempo real." },
{ q: "Sobre qual repertório a reharmonização é mais frequentemente aplicada?", opts: ["A música barroca", "Os standards jazz e as melodias populares conhecidas", "As sinfonias clássicas", "A música contemporânea somente"], a: 1, fb: "Reharmoniza-se sobretudo os standards jazz (Autumn Leaves, All The Things You Are) e as melodias populares. A melodia conhecida pelo ouvinte cria um contraste com os acordes inesperados — o efeito surpresa está no coração da reharmonização." },
{ q: "A substituição 'Dm7 – Db7 – Am7' combina:", opts: ["Duas substituições de trítono", "Substituição de trítono em G7 + substituição diatônica I→VI em CMaj7", "Dois empréstimos modais", "Harmonização paralela + empréstimo modal"], a: 1, fb: "G7→Db7 (trítono) e CMaj7→Am7 (diatônica I→VI) combinadas resultam em Dm7–Db7–Am7. Combinar técnicas multiplica as possibilidades de reharmonização. É assim que Bill Evans construía reharmonizações complexas e sutis." },
{ q: "Coltrane reharmonizou 'My Favorite Things':", opts: ["Transpondo-a em todas as tonalidades", "Mantendo a melodia intacta e criando uma grade modal (dórico) inteiramente nova", "Adicionando acordes diminutos", "Eliminando todas as cadências"], a: 1, fb: "My Favorite Things de Coltrane (1960): melodia de Rodgers & Hammerstein intacta, grade inteiramente modal (ré dórico / mi dórico alternados). A valsa em 3/4 permanece; os acordes são reinventados. Reharmonização completa emblemática." },
{ q: "Autumn Leaves pode ser reharmonizado:", opts: ["Mudando apenas a tonalidade", "Substituindo os V7 por seus substitutos de trítono e substituindo IV por IVm mantendo a melodia", "Apenas o andamento", "Apenas a clave"], a: 1, fb: "Autumn Leaves alterna II–V–I maior e menor. Pode-se substituir os V7 por seus substitutos de trítono (baixo cromático) e substituir FMaj7 por Fm (empréstimo modal). A melodia tão conhecida contrasta com a riqueza harmônica acrescentada." },
{ q: "A técnica de harmonização paralela foi importada de:", opts: ["O contraponto barroco", "O romantismo alemão", "O impressionismo francês (Debussy, Ravel)", "O bebop americano"], a: 2, fb: "Debussy introduziu os acordes paralelos na música clássica (início dos anos 1900) — quintas, quartas, acordes de 7ª paralelos. Os jazzistas americanos os adotam em seguida. Evans, Jarrett e Mehldau são os herdeiros jazz." },
{ q: "Qual das 4 técnicas cria o movimento de baixo mais cromático?", opts: ["Substituição diatônica", "Substituição de trítono (♭II7→I = um semitom)", "Empréstimo modal", "Harmonização paralela"], a: 1, fb: "A substituição de trítono cria uma resolução por semitom descendente — o movimento de baixo mais curto possível. Ex.: Db7→CMaj7: baixo Réb→Do, um semitom. Esse movimento cromático é a característica acústica mais reconhecível dessa técnica." },
{ q: "Qual técnica introduz bemóis inesperados em um contexto maior?", opts: ["Substituição de trítono", "Empréstimo modal (acordes da escala menor paralela)", "Harmonização paralela", "Substituição diatônica"], a: 1, fb: "O empréstimo modal toma acordes da escala menor paralela — que contém bemóis (bIII, bVI, bVII). Esses bemóis inesperados em um contexto maior criam a cor sombria característica. Ex. em C maior: Fm introduz Lab, AbMaj7 introduz Lab e Mib." },
{ q: "Qual técnica conserva exatamente as mesmas notas de tensão que o acorde original?", opts: ["Empréstimo modal", "Harmonização paralela", "Substituição de trítono — o trítono é compartilhado", "Substituição diatônica"], a: 2, fb: "A substituição de trítono compartilha o mesmo trítono entre V7 e ♭II7. G7 e Db7 têm ambos Si e Fa (= Cb) — mesmas notas de tensão, papéis invertidos. É por isso que a resolução parece 'diferente, mas familiar'." },
{ q: "Uma reharmonização de qualidade se reconhece:", opts: ["Pelo número de acordes utilizados", "Pela fluidez da condução de vozes, a compatibilidade de cada nota melódica e a coerência expressiva", "Pelo andamento de execução", "Pela ausência de dissonâncias"], a: 1, fb: "Critérios: (1) cada nota melódica é compatível com o novo acorde, (2) as vozes internas se movem por pequenos intervalos, (3) o efeito expressivo amplifica (e não mascara) a melodia. É técnico E artístico." },
{ q: "Qual é o principal risco na reharmonização?", opts: ["Usar poucos acordes", "Sacrificar a fluidez melódica — se muito radical, a melodia parece 'perdida' sobre os acordes", "Tocar muito suavemente", "Tocar os acordes muito rápido"], a: 1, fb: "O perigo principal: incompatibilidade melodia/acorde. Se uma nota melódica não se encontra no acorde substituído, a sonoridade é agressiva e a melodia flutua no vazio. A fluidez melódica sempre prevalece sobre a sofisticação harmônica." },
{ q: "O que é o 'bVI empréstimo' em C maior?", opts: ["Bm7b5", "AbMaj7 (emprestado de C menor — bVI)", "Am7 (VI diatônico)", "Fm7"], a: 1, fb: "bVI em C maior = AbMaj7. Esse acorde é emprestado de C menor paralelo (onde o 6º grau é bemolizado). AbMaj7 introduz Lab, Mib e Do — cor muito sombria e romântica. Muito usado no jazz post-bop e no pop (Let It Be inclui essa cor)." },
{ q: "Na substituição diatônica, quantas notas comuns idealmente?", opts: ["Nenhuma — os acordes devem contrastar", "Pelo menos 2 notas comuns (idealmente 3)", "Exatamente 1 nota comum", "Todas as notas em comum"], a: 1, fb: "Pelo menos 2 notas comuns garante que a melodia permaneça lógica sobre o acorde substituído. CMaj7–Am7 compartilham 3 notas — substituição muito natural. Menos notas comuns = substituição mais 'arriscada' melodicamente." },
{ q: "Reharmonizar 'Dm7–G7–CMaj7' como 'Dm7–G7–Am7' é uma substituição:", opts: ["Tritônica sobre G7", "Diatônica I→VI sobre CMaj7", "Modal (empréstimo de Am7 do menor)", "Paralela cromática"], a: 1, fb: "Am7 substitui CMaj7 por substituição diatônica I→VI. CMaj7 (I) e Am7 (VIm) compartilham Do, Mi, Sol — três notas comuns. É uma resolução deceptiva suave: a cadência V7→I torna-se V7→VIm, menos definitiva mas muito expressiva." },
];

const questionsEs: Question[] = [
{ q: "¿Qué es la rearmonización?", opts: ["Tocar más notas", "Reemplazar los acordes de una progresión existente por otros conservando la melodía", "Cambiar la melodía de una pieza", "Transponer a otra tonalidad"], a: 1, fb: "La rearmonización conserva la melodía pero reemplaza los acordes. Condición fundamental: cada nota melódica debe ser compatible con el nuevo acorde (fundamental, tercera, quinta, séptima o extensión). Es escultura armónica." },
{ q: "¿Cuál es la condición fundamental de una rearmonización exitosa?", opts: ["Utilizar acordes más complejos", "La nota melódica debe ser compatible con el nuevo acorde", "Siempre permanecer en la misma tonalidad", "Utilizar solo la sustitución de trítono"], a: 1, fb: "Cada nota melódica debe pertenecer al nuevo acorde o ser una tensión aceptable: fundamental, tercera, quinta, séptima o extensión (9ª, 11ª, 13ª). Si la melodía suena mal sobre el nuevo acorde, la rearmonización fracasa." },
{ q: "Una nota melódica es compatible con un acorde si es:", opts: ["Solo la fundamental", "Fundamental, tercera, quinta, séptima o extensión (9ª/11ª/13ª)", "Solo la tercera o la quinta", "Cualquier nota"], a: 1, fb: "Las notas compatibles: fundamental (1), tercera (3), quinta (5), séptima (7) y extensiones (9ª, 11ª, 13ª). Si la melodía canta Mi sobre un acorde rearmonizado, ese acorde debe contener Mi en una de estas posiciones." },
{ q: "Rearmonizar una progresión equivale a:", opts: ["Cambiar el tempo", "Reemplazar total o parcialmente los acordes conservando la melodía intacta", "Añadir nuevos instrumentos", "Cambiar la tonalidad"], a: 1, fb: "Rearmonizar = cambiar los acordes, mantener la melodía. La melodía es el elemento fijo; los acordes de abajo son modificables siempre que cada nota melódica permanezca compatible. Es el arte de encontrar nuevos 'ropajes armónicos' para una misma melodía." },
{ q: "¿Qué par de acordes puede sustituirse en la sustitución diatónica?", opts: ["I y II", "I y VI", "V y IV", "III y VII"], a: 1, fb: "I y VI comparten dos o tres notas comunes (en Do: CMaj7 comparte Mi y Sol con Am7 — también Do). Esta proximidad permite permutarlos sin afectar la melodía. II y IV también se sustituyen (Dm7 y FMaj7 comparten Fa y La)." },
{ q: "En Do mayor, ¿qué acordes se sustituyen en la sustitución diatónica?", opts: ["CMaj7 ↔ Dm7", "CMaj7 ↔ Am7  ·  Dm7 ↔ FMaj7", "G7 ↔ Em7", "Dm7 ↔ G7"], a: 1, fb: "CMaj7 y Am7 comparten Mi y Sol (y Do). FMaj7 y Dm7 comparten Fa y La. Estas notas comunes crean una continuidad armónica suficiente para que la melodía permanezca lógica sobre el acorde sustituido." },
{ q: "¿Por qué I y VI pueden sustituirse?", opts: ["Porque tienen la misma fundamental", "Porque comparten dos o tres notas comunes", "Porque están a distancia de trítono", "Porque tienen la misma calidad mayor/menor"], a: 1, fb: "En Do: CMaj7 = C E G B, Am7 = A C E G. Notas comunes: Do, Mi, Sol. La melodía suena bien sobre Am7 si cantaba Do, Mi o Sol sobre CMaj7. Más notas comunes = sustitución más natural." },
{ q: "La sustitución diatónica 'II ↔ IV' en Do mayor corresponde a:", opts: ["Dm7 ↔ G7", "Dm7 ↔ FMaj7", "Am7 ↔ Em7", "CMaj7 ↔ FMaj7"], a: 1, fb: "IIm7 = Dm7 (D F A C), IV = FMaj7 (F A C E). Notas comunes: Fa, La, Do. Estos dos acordes tienen una función de subdominante similar y pueden sustituirse en muchos contextos." },
{ q: "Reemplazar CMaj7 por Am7 (I → VI) crea qué efecto:", opts: ["Una resolución más fuerte", "Un ligero color menor, más suave — 'resolución deceptiva suave'", "Una tensión máxima", "Un cambio de tonalidad"], a: 1, fb: "Am7 comparte las notas de CMaj7 pero su fundamento menor crea un color más suave, a veces melancólico. Es una 'cadencia deceptiva suave' — la resolución esperada sobre I llega pero teñida de VIm, menos definitiva." },
{ q: "El sustituto de trítono de G7 es:", opts: ["F#7", "Db7", "Ab7", "C#7"], a: 1, fb: "Db7 está situado un trítono (6 semitonos) por encima de G7. Db7 (Db F Ab Cb) comparte el mismo trítono que G7 (Si/Cb y Fa) — las notas de tensión son idénticas pero sus roles se invierten. El bajo desciende un semitono Db→C." },
{ q: "¿Qué comparten G7 y Db7, haciendo posible la sustitución de trítono?", opts: ["La fundamental", "La misma quinta", "El mismo trítono — Si y Fa (notas de tensión)", "La misma séptima"], a: 2, fb: "G7 contiene Si–Fa (trítono). Db7 contiene Fa–Cb (= Si, enarmónico). Estas dos notas de tensión son idénticas en ambos acordes pero sus nombres se invierten. Es este intercambio el que hace coherente la sustitución armónicamente." },
{ q: "¿Qué efecto crea la sustitución de trítono sobre el bajo?", opts: ["Un salto de quinta", "Un movimiento cromático descendente (semitono) hacia I", "Un movimiento ascendente por semitonos", "Un bajo fijo"], a: 1, fb: "Db7 → CMaj7: el bajo desciende un semitono. Comparado con G7 → CMaj7 (quinta descendente), es mucho más elegante. Este movimiento cromático es característico del jazz bebop y de la rearmonización jazz." },
{ q: "El sustituto de trítono de D7 (dominante de GMaj7) es:", opts: ["Eb7", "Ab7", "Bb7", "F#7"], a: 1, fb: "Un trítono por encima de D (Re) = Ab (La bemol). Ab7 es el sustituto de trítono de D7. En II–V–I de G: Am7–D7–GMaj7 puede convertirse en Am7–Ab7–GMaj7 (bajo La–Lab–Sol, descenso cromático)." },
{ q: "¿Por qué funciona armónicamente la sustitución de trítono?", opts: ["Porque los dos acordes tienen la misma quinta", "Porque V7 y ♭II7 comparten las mismas notas de tensión (el trítono), solo con los roles invertidos", "Porque están en la misma escala", "Porque la fundamental permanece igual"], a: 1, fb: "El trítono de V7 (ej. Si–Fa de G7) es también el trítono de ♭II7 (Fa–Si de Db7). Ambos acordes crean la misma tensión de resolución hacia I — mismo 'combustible', fundamental diferente. El bajo desciende por semitono en lugar de quinta." },
{ q: "En 'Dm7 – Db7 – CMaj7', Db7 reemplaza qué acorde original:", opts: ["Dm7 (II)", "G7 (V) por sustitución de trítono", "Am7 (VI)", "Em7 (III)"], a: 1, fb: "Db7 es el sustituto de trítono de G7. La progresión original Dm7–G7–CMaj7 se convierte en Dm7–Db7–CMaj7. El bajo D–Db–C desciende cromáticamente, haciendo la progresión muy elegante." },
{ q: "¿Qué es un préstamo modal en rearmonización?", opts: ["Usar un acorde de otro instrumento", "Reemplazar un acorde por su homónimo de la escala menor paralela", "Usar el modo dórico", "Tomar prestados acordes del jazz modal"], a: 1, fb: "El préstamo modal toma un acorde de la tonalidad homónima menor. En Do mayor, se toma prestado de Do menor: Fm (IVm), Cm (Im), AbMaj7 (bVI), Bb7 (bVII). Estos acordes aportan un color oscuro y modal en un contexto mayor." },
{ q: "En Do mayor, 'FMaj7 → Fm' es un préstamo de:", opts: ["La escala de Fa mayor", "Do menor paralelo (IVm = Fm en la escala homónima menor)", "La escala de Re dórico", "La escala pentatónica"], a: 1, fb: "Fm (F Ab C Eb) es el IVº grado de Do menor. Se toma prestado de la tonalidad homónima menor. Lab (3ª de Fm) crea el color oscuro. Bill Evans usaba frecuentemente esta 'bemolización' del IV en sus standards." },
{ q: "¿Qué nota característica aparece cuando se reemplaza FMaj7 por Fm en Do mayor?", opts: ["Fa#", "Lab (bIII de Do menor)", "Do#", "Sib"], a: 1, fb: "Fm = F Ab C Eb. El Lab (Ab) es la nota extraña procedente de Do menor. Esta bemolización de la tercera (La→Lab) caracteriza el préstamo modal — color oscuro inmediatamente reconocible." },
{ q: "¿Qué acordes pueden tomarse prestados de Do menor paralelo?", opts: ["Solo Cm", "Fm (IVm), Cm (Im), AbMaj7 (bVI), Bb7 (bVII), EbMaj7 (bIII)", "Solo Fm y Cm", "G7 y D7 solamente"], a: 1, fb: "La escala de Do menor proporciona: Im=Cm, IIm7b5=Dm7b5, bIII=EbMaj7, IVm=Fm, V7=G7, bVI=AbMaj7, bVII=Bb7. Todos pueden tomarse prestados en Do mayor. Los más comunes: Fm, AbMaj7, Bb7 (por sus bemoles expresivos)." },
{ q: "¿Por qué el préstamo modal crea un efecto conmovedor?", opts: ["Porque es más fácil de tocar", "Porque introduce bemoles inesperados que oscurecen momentáneamente un color mayor", "Porque suprime el trítono", "Porque lo impone la forma AABA"], a: 1, fb: "Los préstamos modales (IV→IVm, I→Im) introducen bemoles procedentes del menor paralelo — Lab, Mib, Sib. Estos colores oscuros inesperados en un contexto mayor crean un contraste expresivo poderoso — sello del sonido de Bill Evans." },
{ q: "¿Qué es la armonización paralela?", opts: ["Tocar dos melodías simultáneamente", "Desplazar el mismo tipo de acorde cromáticamente bajo la melodía", "Armonizar a la tercera", "Doblar las voces a la octava"], a: 1, fb: "La armonización paralela desplaza un tipo de acorde idéntico (ej. Maj7) cromáticamente o por tonos siguiendo la melodía. CMaj7–DbMaj7–DMaj7: misma estructura, bases sucesivas. Técnica impresionista adoptada por el jazz." },
{ q: "CMaj7 → DbMaj7 → DMaj7 es un ejemplo de:", opts: ["Sustitución de trítono sucesiva", "Armonización paralela cromática ascendente", "Sustitución diatónica", "Ciclo de quintas"], a: 1, fb: "Mismo tipo de acorde (Maj7) desplazado cromáticamente (C→Db→D). La conducción de voces es mecánica — todas las voces se mueven el mismo intervalo. La melodía flotando por encima crea el interés armónico." },
{ q: "¿Qué compositor está principalmente asociado a la armonización paralela?", opts: ["Bach", "Beethoven", "Debussy", "Vivaldi"], a: 2, fb: "Debussy sistematizó los acordes paralelos en sus preludios y nocturnos. El impresionismo francés introdujo esta técnica que el jazz adoptó — especialmente Bill Evans en My Foolish Heart y Peace Piece." },
{ q: "En la armonización paralela, ¿qué crea el interés armónico?", opts: ["La complejidad de los acordes", "La melodía — los acordes se desplazan en bloque bajo ella", "El movimiento de bajo rápido", "Las notas de tensión"], a: 1, fb: "Los acordes paralelos son 'neutros' en sí mismos. Es la melodía inmutable la que crea la lógica y el interés. La sucesión cromática de acordes crea el efecto impresionista; la melodía guía al oyente." },
{ q: "Si la melodía canta 'Mi' sobre un acorde rearmonizado, ¿qué acorde conviene?", opts: ["Fm7 (Mi ausente)", "CMaj7 (Mi = 3ª)", "Dm7b5 (Mi ausente)", "Bb7 (Mi ausente)"], a: 1, fb: "CMaj7 = C E G B. Mi (E) es la 3ª de CMaj7 — nota constitutiva. La melodía Mi es perfectamente compatible. Regla: la nota melódica debe ser 1, 3, 5, 7 o extensión del acorde." },
{ q: "Si la melodía canta 'La' sobre un acorde rearmonizado, ¿cuál conviene?", opts: ["Dm7 (La = 5ª)", "FMaj7 (La = 3ª)", "Am7 (La = fundamental)", "Todos funcionan"], a: 3, fb: "La (A) es: 5ª de Dm7, 3ª de FMaj7, fundamental de Am7. Los tres acordes son compatibles con la melodía La. Es por eso que la rearmonización ofrece tantas posibilidades — una misma nota puede pertenecer a numerosos acordes." },
{ q: "Para verificar la compatibilidad melodía/acorde, la nota debe ser:", opts: ["Más alta que el bajo", "1, 3, 5, 7 o extensión (9ª, 11ª, 13ª) del acorde", "En la misma octava que la fundamental", "Inferior a la quinta"], a: 1, fb: "Regla universal: fundamental (1), tercera (3), quinta (5), séptima (7) o extensión (9ª, 11ª, 13ª). Las notas fuera de estas categorías crean fricciones involuntarias. Una b9 no intencional suena mal." },
{ q: "¿Por qué 'Si' (B natural) es problemático sobre un acorde Fm?", opts: ["Porque Si es demasiado grave", "Porque Si (= 4ª aumentada / trítono de Fm) no es una extensión natural de un acorde menor", "Porque Si siempre es disonante", "Porque Si es demasiado agudo"], a: 1, fb: "Fm = F Ab C Eb. Si (B) es la 4ª aumentada de Fm — un trítono respecto a la fundamental Fa. No es una extensión natural. Si la melodía canta Si sobre Fm, la rearmonización suena mal: hay que elegir otro acorde." },
{ q: "En 'Dm7 – Db7 – CMaj7' con melodía Sol–Sol–Sol, ¿es Db7 compatible?", opts: ["No — Sol es la 4ª bemolizada de Db7, muy disonante", "Sí — Sol es la quinta de Db7", "No — Sol nunca es compatible", "Sí — Sol siempre es posible"], a: 0, fb: "Db7 = Db F Ab Cb. Sol (G) respecto a Db: es la cuarta aumentada (= trítono). Muy disonante, no natural. Antes de validar una rearmonización, verificar cada nota melódica sobre cada nuevo acorde." },
{ q: "Bill Evans está asociado a qué corriente del jazz:", opts: ["El bebop de los años 1940", "El jazz cool y post-bop de los años 1950–70", "El free jazz", "El dixieland"], a: 1, fb: "Bill Evans (1929–1980) es una figura central del jazz cool y post-bop. Su trabajo con el sexteto de Miles Davis (Kind of Blue, 1959) y su trío definieron un sonido introspectivo y armónicamente sofisticado." },
{ q: "Bill Evans es famoso por sus rearmonizaciones en las que:", opts: ["Suprime todos los acordes de paso", "Añade préstamos modales, extensiones y sustituciones sutiles que transforman progresiones simples en obras sofisticadas", "Toca únicamente en menor", "Evita las disonancias"], a: 1, fb: "Evans transformaba standards simples (Autumn Leaves, Waltz for Debby) mediante préstamos modales (IVm, bVI), extensiones (9ª, b11), sustituciones de trítono delicadas y una conducción de voces impecable." },
{ q: "En 'My Foolish Heart', Evans utiliza especialmente:", opts: ["El modo locrio exclusivamente", "Acordes paralelos cromáticos y préstamos al menor paralelo", "El jazz blues de 12 compases", "Únicamente tríadas"], a: 1, fb: "Evans rearmoniza My Foolish Heart con acordes paralelos cromáticos (impresión debussysta) y préstamos modales (IVm, bVI) que oscurecen el color. Rearmonización 'en bloques' característica de su estilo." },
{ q: "¿Cuál es la contribución principal de Bill Evans a la rearmonización jazz?", opts: ["Inventar la sustitución de trítono", "Mostrar que los standards pueden transformarse armónicamente mediante sustituciones sutiles sin perturbar nunca la melodía", "Crear la forma blues", "Introducir el modo dórico"], a: 1, fb: "Evans demostró que una rearmonización puede ser sutil y preservar el 'carácter' de un standard. Su versión de Waltz for Debby ilustra cómo rearmonizar para amplificar — y no enmascarar — la belleza original." },
{ q: "Keith Jarrett y Brad Mehldau continuaron la tradición de:", opts: ["Charlie Parker (bebop puro)", "Bill Evans — rearmonización introspectiva, préstamos modales y conducción de voces cuidadosa", "Miles Davis (eléctrico)", "Oscar Peterson (stride)"], a: 1, fb: "Jarrett y Mehldau heredan directamente de Evans: misma atención a la conducción de voces, mismo uso de préstamos modales, misma capacidad de rearmonizar un standard conservando su identidad emocional." },
{ q: "Brad Mehldau es conocido por rearmonizar canciones de:", opts: ["Beethoven", "Radiohead, Nick Drake y otros artistas pop/rock", "Vivaldi", "Wagner"], a: 1, fb: "Brad Mehldau rearmoniza canciones pop (Radiohead: Knives Out, Exit Music for a Film; Nick Drake) con el lenguaje jazz (extensiones, sustituciones, préstamos modales). Rearmonización cross-género — melodía pop, armonía jazz." },
{ q: "¿Por qué la conducción de voces es crucial en rearmonización?", opts: ["Porque determina el tempo", "Porque los cambios bruscos de acordes crean saltos poco elegantes — la fluidez de las voces internas es un criterio de calidad", "Porque suprime las disonancias", "Porque la impone Fux"], a: 1, fb: "Una rearmonización puede ser técnicamente correcta (notas compatibles) pero sonar bruscamente si las voces internas hacen grandes saltos. La buena rearmonización desplaza las voces por semitonos o tonos — mínimo movimiento, máxima fluidez." },
{ q: "¿Qué regla de conducción de voces se aplica en rearmonización?", opts: ["Las voces siempre deben subir", "Preferir el movimiento conjunto (semitono, tono) para las voces internas", "Nunca doblar la fundamental", "Siempre colocar la melodía en la voz más grave"], a: 1, fb: "En rearmonización: movimiento de voces por pequeños intervalos (conjunto). G7 → Db7: las voces internas Si–Re–Fa encuentran fácilmente Fa–Lab–Si en Db7 por movimiento de semitonos. Es lo que Evans dominaba perfectamente." },
{ q: "¿Cómo facilita la sustitución de trítono la conducción de voces?", opts: ["Porque suprime una voz", "Porque las notas de tensión (trítono) compartidas entre V7 y ♭II7 permiten una conducción muy fluida", "Porque solo tiene 2 notas", "Porque siempre está en posición cerrada"], a: 1, fb: "G7 (G B D F) y Db7 (Db F Ab Cb) comparten Si/Cb y Fa. La sustitución de trítono crea un acorde vecino con notas comunes — las voces apenas necesitan moverse. Es por eso que esta sustitución parece 'suave' a pesar del cambio radical de fundamental." },
{ q: "¿Qué es rearmonizar 'por bloques'?", opts: ["Cambiar todos los acordes de una sola vez", "Modificar un acorde a la vez, dejando el resto intacto", "Agrupar los acordes de 4 en 4", "Tocar todos los acordes simultáneamente"], a: 1, fb: "Rearmonizar por bloques = modificar un acorde a la vez en la progresión. Ej. cambiar solo V7 por sustitución de trítono, dejando los demás acordes originales. Es el enfoque más seguro — se controla el impacto de cada cambio." },
{ q: "La 'rearmonización completa' consiste en:", opts: ["Tocar más fuerte", "Reemplazar completamente la grilla original por una nueva progresión conservando la melodía", "Transponer a otra tonalidad", "Tocar sin acordes"], a: 1, fb: "La rearmonización completa reconstruye totalmente la grilla. La melodía permanece; los acordes de abajo son completamente nuevos. Ejemplo: Coltrane toma My Favorite Things (melodía intacta) y le crea una grilla modal totalmente diferente." },
{ q: "¿Por qué se rearmoniza un standard jazz?", opts: ["Porque los acordes originales son incorrectos", "Para renovar la expresión artística, explorar nuevos colores armónicos y personalizar la interpretación", "Porque lo imponen las reglas del jazz", "Para facilitar la improvisación"], a: 1, fb: "La rearmonización es una herramienta de expresión. Permite al músico 'firmar' su versión de un standard, explorar nuevas emociones armónicas, sorprender al oyente familiarizado con la versión original. Es composición en tiempo real." },
{ q: "¿A qué repertorio se aplica más frecuentemente la rearmonización?", opts: ["La música barroca", "Los standards jazz y las melodías populares conocidas", "Las sinfonías clásicas", "La música contemporánea únicamente"], a: 1, fb: "Se rearmoniza sobre todo los standards jazz (Autumn Leaves, All The Things You Are) y las melodías populares. La melodía conocida por el oyente crea un contraste con los acordes inesperados — el efecto sorpresa está en el corazón de la rearmonización." },
{ q: "La sustitución 'Dm7 – Db7 – Am7' combina:", opts: ["Dos sustituciones de trítono", "Sustitución de trítono en G7 + sustitución diatónica I→VI en CMaj7", "Dos préstamos modales", "Armonización paralela + préstamo modal"], a: 1, fb: "G7→Db7 (trítono) y CMaj7→Am7 (diatónica I→VI) combinadas dan Dm7–Db7–Am7. Combinar técnicas multiplica las posibilidades de rearmonización. Así construía Bill Evans rearmonizaciones complejas y sutiles." },
{ q: "Coltrane rearmonizó 'My Favorite Things':", opts: ["Transponiéndola en todas las tonalidades", "Conservando la melodía intacta y creando una grilla modal (dórico) completamente nueva", "Añadiendo acordes disminuidos", "Suprimiendo todas las cadencias"], a: 1, fb: "My Favorite Things de Coltrane (1960): melodía de Rodgers & Hammerstein intacta, grilla completamente modal (re dórico / mi dórico alternados). El vals 3/4 permanece; los acordes son reinventados. Rearmonización completa emblemática." },
{ q: "Autumn Leaves puede rearmonizarse:", opts: ["Cambiando solo la tonalidad", "Sustituyendo los V7 por sus sustitutos de trítono y reemplazando IV por IVm conservando la melodía", "Solo el tempo", "Solo la clave"], a: 1, fb: "Autumn Leaves alterna II–V–I mayor y menor. Se pueden sustituir los V7 por sus sustitutos de trítono (bajo cromático) y reemplazar FMaj7 por Fm (préstamo modal). La melodía tan conocida contrasta con la riqueza armónica añadida." },
{ q: "La técnica de armonización paralela fue importada de:", opts: ["El contrapunto barroco", "El romanticismo alemán", "El impresionismo francés (Debussy, Ravel)", "El bebop americano"], a: 2, fb: "Debussy introdujo los acordes paralelos en la música clásica (primeros años 1900) — quintas, cuartas, acordes de 7ª paralelos. Los jazzistas americanos lo adoptan después. Evans, Jarrett y Mehldau son sus herederos jazz." },
{ q: "¿Cuál de las 4 técnicas crea el movimiento de bajo más cromático?", opts: ["Sustitución diatónica", "Sustitución de trítono (♭II7→I = un semitono)", "Préstamo modal", "Armonización paralela"], a: 1, fb: "La sustitución de trítono crea una resolución por semitono descendente — el movimiento de bajo más corto posible. Ej. Db7→CMaj7: bajo Reb→Do, un semitono. Este movimiento cromático es la característica acústica más reconocible de esta técnica." },
{ q: "¿Qué técnica introduce bemoles inesperados en un contexto mayor?", opts: ["Sustitución de trítono", "Préstamo modal (acordes de la escala menor paralela)", "Armonización paralela", "Sustitución diatónica"], a: 1, fb: "El préstamo modal toma acordes de la escala menor paralela — que contiene bemoles (bIII, bVI, bVII). Estos bemoles inesperados en un contexto mayor crean el color oscuro característico. Ej. en Do mayor: Fm introduce Lab, AbMaj7 introduce Lab y Mib." },
{ q: "¿Qué técnica conserva exactamente las mismas notas de tensión que el acorde original?", opts: ["Préstamo modal", "Armonización paralela", "Sustitución de trítono — el trítono es compartido", "Sustitución diatónica"], a: 2, fb: "La sustitución de trítono comparte el mismo trítono entre V7 y ♭II7. G7 y Db7 tienen ambos Si y Fa (= Cb) — mismas notas de tensión, roles invertidos. Es por eso que la resolución parece 'diferente pero familiar'." },
{ q: "Una rearmonización de calidad se reconoce por:", opts: ["El número de acordes utilizados", "La fluidez de la conducción de voces, la compatibilidad de cada nota melódica y la coherencia expresiva", "El tempo de ejecución", "La ausencia de disonancias"], a: 1, fb: "Criterios: (1) cada nota melódica es compatible con el nuevo acorde, (2) las voces internas se mueven por pequeños intervalos, (3) el efecto expresivo amplifica (no enmascara) la melodía. Es técnico Y artístico." },
{ q: "¿Qué riesgo mayor existe en la rearmonización?", opts: ["Usar muy pocos acordes", "Sacrificar la fluidez melódica — si es demasiado radical, la melodía parece 'perdida' sobre los acordes", "Tocar demasiado suavemente", "Tocar los acordes demasiado rápido"], a: 1, fb: "El peligro principal: incompatibilidad melodía/acorde. Si una nota melódica no se encuentra en el acorde sustituido, la sonoridad es agresiva y la melodía flota en el vacío. La fluidez melódica siempre prevalece sobre la sofisticación armónica." },
{ q: "¿Qué es el 'préstamo bVI' en Do mayor?", opts: ["Bm7b5", "AbMaj7 (prestado de Do menor — bVI)", "Am7 (VI diatónico)", "Fm7"], a: 1, fb: "bVI en Do mayor = AbMaj7. Este acorde es prestado de Do menor paralelo (donde el 6º grado es bemolizado). AbMaj7 introduce Lab, Mib y Do — color muy oscuro y romántico. Muy usado en el jazz post-bop y el pop (Let It Be incluye este color)." },
{ q: "En la sustitución diatónica, ¿cuántas notas comunes idealmente?", opts: ["Ninguna — los acordes deben contrastar", "Al menos 2 notas comunes (idealmente 3)", "Exactamente 1 nota común", "Todas las notas en común"], a: 1, fb: "Al menos 2 notas comunes garantiza que la melodía permanezca lógica sobre el acorde sustituido. CMaj7–Am7 comparten 3 notas — sustitución muy natural. Menos notas comunes = sustitución más 'arriesgada' melódicamente." },
{ q: "Rearmonizar 'Dm7–G7–CMaj7' en 'Dm7–G7–Am7' es una sustitución:", opts: ["Tritónica sobre G7", "Diatónica I→VI sobre CMaj7", "Modal (préstamo de Am7 del menor)", "Paralela cromática"], a: 1, fb: "Am7 reemplaza CMaj7 por sustitución diatónica I→VI. CMaj7 (I) y Am7 (VIm) comparten Do, Mi, Sol — tres notas comunes. Es una resolución deceptiva suave: la cadencia V7→I se convierte en V7→VIm, menos definitiva pero muy expresiva." },
];

